{"content":"import React, { useState, useCallback } from 'react';
import {
  Radar, TrendingUp, TrendingDown, Eye, MessageSquare, BarChart3,
  Search, Loader2, AlertTriangle, ChevronRight, ExternalLink,
  ThumbsUp, ThumbsDown, Minus, RefreshCw, Sparkles, Zap, ArrowRight
} from 'lucide-react';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  BarChart, Bar, Cell, Legend
} from 'recharts';
import { runMonitoringScan } from '../services/ai-monitoring';
import { MonitoringResult, AIEngine } from '../types/ai-monitoring';
import { User } from '../types';

interface AiMonitoringProps {
  onBack: () => void;
  onNavigate: (view: any) => void;
  onDeductCredits: (amount: number) => boolean;
  user: User | null;
}

const ENGINE_COLORS: Record<AIEngine, string> = {
  ChatGPT: '#10b981',
  Claude: '#a855f7',
  Perplexity: '#3b82f6',
  Gemini: '#f59e0b',
};

const ENGINE_BG: Record<AIEngine, string> = {
  ChatGPT: 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
  Claude: 'bg-purple-500/10 text-purple-400 border-purple-500/20',
  Perplexity: 'bg-blue-500/10 text-blue-400 border-blue-500/20',
  Gemini: 'bg-amber-500/10 text-amber-400 border-amber-500/20',
};

const SENTIMENT_CONFIG = {
  positive: { icon: ThumbsUp, color: 'text-emerald-400', bg: 'bg-emerald-500/10', label: 'Positif' },
  neutral: { icon: Minus, color: 'text-gray-400', bg: 'bg-gray-500/10', label: 'Neutre' },
  negative: { icon: ThumbsDown, color: 'text-red-400', bg: 'bg-red-500/10', label: 'Negatif' },
};

const CREDIT_COST = 5;

const AiMonitoring: React.FC<AiMonitoringProps> = ({ onBack, onNavigate, onDeductCredits, user }) => {
  const [brandName, setBrandName] = useState('');
  const [url, setUrl] = useState('');
  const [period, setPeriod] = useState<'7d' | '30d' | '90d'>('30d');
  const [isScanning, setIsScanning] = useState(false);
  const [result, setResult] = useState<MonitoringResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleScan = useCallback(async () => {
    if (!brandName.trim() || !url.trim()) {
      setError('Veuillez saisir un nom de marque et une URL.');
      return;
    }

    const credited = onDeductCredits(CREDIT_COST);
    if (!credited) return;

    setError(null);
    setIsScanning(true);

    try {
      const data = await runMonitoringScan(brandName.trim(), url.trim(), period);
      setResult(data);
    } catch (err) {
      setError('Erreur lors du scan. Veuillez reessayer.');
      console.error(err);
    } finally {
      setIsScanning(false);
    }
  }, [brandName, url, period, onDeductCredits]);

  const handleRescan = useCallback(async () => {
    if (!result) return;

    const credited = onDeductCredits(CREDIT_COST);
    if (!credited) return;

    setIsScanning(true);
    try {
      const data = await runMonitoringScan(result.brandName, result.url, period);
      setResult(data);
    } catch (err) {
      setError('Erreur lors du rescan.');
    } finally {
      setIsScanning(false);
    }
  }, [result, period, onDeductCredits]);

  // ── Custom tooltip for Recharts ──
  const CustomTooltip = ({ active, payload, label }: any) => {
    if (!active || !payload || !payload.length) return null;
    return (
      <div className="bg-[#1a1d21] border border-white/10 rounded-xl px-4 py-3 shadow-xl">
        <p className="text-xs text-gray-400 mb-2">{label}</p>
        {payload.map((entry: any, index: number) => (
          <p key={index} className="text-sm font-medium" style={{ color: entry.color }}>
            {entry.name}: {entry.value}
          </p>
        ))}
      </div>
    );
  };

  // ── Render input form ──
  if (!result) {
    return (
      <div className="w-full px-6 py-8 animate-in fade-in duration-500">
        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
          <div className="flex items-center gap-4">
            <div className="p-3 rounded-2xl bg-gradient-to-br from-purple-500/20 to-violet-600/20 border border-purple-500/20">
              <Radar size={28} className="text-purple-400" />
            </div>
            <div>
              <h1 className="text-3xl font-bold text-white">Monitoring <span className="bg-gradient-to-r from-purple-400 to-violet-400 bg-clip-text text-transparent">IA</span></h1>
              <p className="text-sm text-gray-500 mt-1">Suivez vos citations sur ChatGPT, Claude, Perplexity & Gemini</p>
            </div>
          </div>
          <span className="bg-purple-500/10 text-purple-400 text-xs font-bold px-3 py-1.5 rounded-full border border-purple-500/20 flex items-center gap-1.5">
            <Zap size={12} /> {CREDIT_COST} Gas / scan
          </span>
        </div>

        {/* Input card */}
        <div className="max-w-2xl mx-auto">
          <div className="ninja-card p-8 space-y-6">
            <div className="text-center mb-2">
              <h2 className="text-xl font-bold text-white mb-2">Lancer un scan de monitoring</h2>
              <p className="text-sm text-gray-500">Analysez la presence de votre marque dans les reponses des IA generatives</p>
            </div>

            {/* Brand name */}
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">Nom de la marque</label>
              <input
                type="text"
                value={brandName}
                onChange={(e) => setBrandName(e.target.value)}
                placeholder="Ex: CitedBy.ai"
                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl py-3 px-4 text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50 transition-all"
              />
            </div>

            {/* URL */}
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">URL du site</label>
              <input
                type="text"
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                placeholder="https://example.com"
                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl py-3 px-4 text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50 transition-all"
              />
            </div>

            {/* Period selector */}
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">Periode d'analyse</label>
              <div className="flex gap-3">
                {(['7d', '30d', '90d'] as const).map((p) => (
                  <button
                    key={p}
                    onClick={() => setPeriod(p)}
                    className={`flex-1 py-2.5 rounded-xl text-sm font-medium transition-all duration-200 ${
                      period === p
                        ? 'bg-gradient-to-r from-purple-600 to-violet-600 text-white shadow-lg shadow-purple-900/30'
                        : 'bg-white/[0.04] border border-white/[0.08] text-gray-400 hover:text-white hover:bg-white/[0.06]'
                    }`}
                  >
                    {p === '7d' ? '7 jours' : p === '30d' ? '30 jours' : '90 jours'}
                  </button>
                ))}
              </div>
            </div>

            {error && (
              <div className="flex items-center gap-2 px-4 py-3 rounded-xl bg-red-500/10 border border-red-500/20 text-red-400 text-sm">
                <AlertTriangle size={16} />
                {error}
              </div>
            )}

            {/* Scan button */}
            <button
              onClick={handleScan}
              disabled={isScanning || !brandName.trim() || !url.trim()}
              className="w-full py-3.5 bg-gradient-to-r from-purple-600 to-violet-600 hover:from-purple-500 hover:to-violet-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-semibold rounded-xl transition-all duration-200 shadow-lg shadow-purple-900/30 flex items-center justify-center gap-2"
            >
              {isScanning ? (
                <>
                  <Loader2 size={18} className="animate-spin" />
                  Analyse en cours...
                </>
              ) : (
                <>
                  <Search size={18} />
                  Lancer le scan ({CREDIT_COST} Gas)
                </>
              )}
            </button>

            {/* Engine badges */}
            <div className="flex items-center justify-center gap-3 pt-2">
              {(['ChatGPT', 'Claude', 'Perplexity', 'Gemini'] as AIEngine[]).map((engine) => (
                <span key={engine} className={`text-xs px-2.5 py-1 rounded-full border ${ENGINE_BG[engine]}`}>
                  {engine}
                </span>
              ))}
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ── Render results ──
  const sentimentScore = result.overallSentiment.positive - result.overallSentiment.negative;
  const sentimentLabel = sentimentScore > 20 ? 'Positif' : sentimentScore > -10 ? 'Mixte' : 'Negatif';
  const sentimentColor = sentimentScore > 20 ? 'text-emerald-400' : sentimentScore > -10 ? 'text-amber-400' : 'text-red-400';

  return (
    <div className="w-full px-6 py-8 animate-in fade-in duration-500">
      {/* Header with brand info */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div className="flex items-center gap-4">
          <div className="p-3 rounded-2xl bg-gradient-to-br from-purple-500/20 to-violet-600/20 border border-purple-500/20">
            <Radar size={28} className="text-purple-400" />
          </div>
          <div>
            <h1 className="text-2xl font-bold text-white flex items-center gap-2">
              {result.brandName}
              <span className="text-sm font-normal text-gray-500 hidden md:inline">{result.url}</span>
            </h1>
            <p className="text-sm text-gray-500 mt-0.5">
              Scan du {new Date(result.scanDate).toLocaleDateString('fr-FR')} &mdash; Periode: {period === '7d' ? '7 jours' : period === '30d' ? '30 jours' : '90 jours'}
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {/* Period selector */}
          <div className="flex bg-white/[0.04] border border-white/[0.08] rounded-xl overflow-hidden">
            {(['7d', '30d', '90d'] as const).map((p) => (
              <button
                key={p}
                onClick={() => setPeriod(p)}
                className={`px-3.5 py-2 text-xs font-medium transition-all ${
                  period === p
                    ? 'bg-purple-600 text-white'
                    : 'text-gray-500 hover:text-white hover:bg-white/[0.06]'
                }`}
              >
                {p === '7d' ? '7j' : p === '30d' ? '30j' : '90j'}
              </button>
            ))}
          </div>
          <button
            onClick={handleRescan}
            disabled={isScanning}
            className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-purple-600 to-violet-600 hover:from-purple-500 hover:to-violet-500 text-white text-sm font-medium rounded-xl transition-all shadow-lg shadow-purple-900/30 disabled:opacity-50"
          >
            {isScanning ? <Loader2 size={14} className="animate-spin" /> : <RefreshCw size={14} />}
            Rescanner ({CREDIT_COST} Gas)
          </button>
        </div>
      </div>

      {/* Loading overlay */}
      {isScanning && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center">
          <div className="bg-[#1a1d21] border border-white/10 rounded-2xl p-8 text-center max-w-sm">
            <Loader2 size={40} className="text-purple-400 animate-spin mx-auto mb-4" />
            <h3 className="text-lg font-bold text-white mb-2">Scan en cours...</h3>
            <p className="text-sm text-gray-500">Analyse des citations IA sur 4 moteurs</p>
          </div>
        </div>
      )}

      {/* ── KPI Cards ── */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        {/* Total Citations */}
        <div className="ninja-card p-5">
          <div className="flex items-center justify-between mb-3">
            <span className="text-xs text-gray-500 font-medium uppercase tracking-wider">Citations totales</span>
            <div className="p-2 rounded-xl bg-purple-500/10">
              <MessageSquare size={16} className="text-purple-400" />
            </div>
          </div>
          <div className="text-3xl font-bold text-white mb-1">{result.totalCitations}</div>
          <div className={`flex items-center gap-1 text-xs font-medium ${result.trend >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
            {result.trend >= 0 ? <TrendingUp size={12} /> : <TrendingDown size={12} />}
            {result.trend >= 0 ? '+' : ''}{result.trend}% vs periode prec.
          </div>
        </div>

        {/* Share of Voice */}
        <div className="ninja-card p-5">
          <div className="flex items-center justify-between mb-3">
            <span className="text-xs text-gray-500 font-medium uppercase tracking-wider">Part de voix</span>
            <div className="p-2 rounded-xl bg-blue-500/10">
              <Eye size={16} className="text-blue-400" />
            </div>
          </div>
          <div className="text-3xl font-bold text-white mb-1">{result.shareOfVoice}%</div>
          <div className="w-full bg-white/[0.06] rounded-full h-1.5 mt-2">
            <div className="bg-gradient-to-r from-blue-500 to-purple-500 rounded-full h-1.5 transition-all duration-500" style={{ width: `${Math.min(result.shareOfVoice, 100)}%` }} />
          </div>
        </div>

        {/* Sentiment */}
        <div className="ninja-card p-5">
          <div className="flex items-center justify-between mb-3">
            <span className="text-xs text-gray-500 font-medium uppercase tracking-wider">Sentiment</span>
            <div className={`p-2 rounded-xl ${sentimentScore > 20 ? 'bg-emerald-500/10' : sentimentScore > -10 ? 'bg-amber-500/10' : 'bg-red-500/10'}`}>
              {sentimentScore > 20 ? <ThumbsUp size={16} className="text-emerald-400" /> : sentimentScore > -10 ? <Minus size={16} className="text-amber-400" /> : <ThumbsDown size={16} className="text-red-400" />}
            </div>
          </div>
          <div className={`text-3xl font-bold ${sentimentColor}`}>{sentimentLabel}</div>
          <div className="flex gap-1 mt-2">
            <div className="bg-emerald-500/30 rounded-full h-1.5 transition-all" style={{ width: `${result.overallSentiment.positive}%` }} />
            <div className="bg-gray-500/30 rounded-full h-1.5 transition-all" style={{ width: `${result.overallSentiment.neutral}%` }} />
            <div className="bg-red-500/30 rounded-full h-1.5 transition-all" style={{ width: `${result.overallSentiment.negative}%` }} />
          </div>
        </div>

        {/* Trend */}
        <div className="ninja-card p-5">
          <div className="flex items-center justify-between mb-3">
            <span className="text-xs text-gray-500 font-medium uppercase tracking-wider">Tendance</span>
            <div className={`p-2 rounded-xl ${result.trend >= 0 ? 'bg-emerald-500/10' : 'bg-red-500/10'}`}>
              {result.trend >= 0 ? <TrendingUp size={16} className="text-emerald-400" /> : <TrendingDown size={16} className="text-red-400" />}
            </div>
          </div>
          <div className={`text-3xl font-bold ${result.trend >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
            {result.trend >= 0 ? '+' : ''}{result.trend}%
          </div>
          <div className="text-xs text-gray-500 mt-1">Evolution sur la periode</div>
        </div>
      </div>

      {/* ── Charts Row ── */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
        {/* Area Chart - Citations over time */}
        <div className="ninja-card p-6 lg:col-span-2">
          <h3 className="text-lg font-bold text-white mb-1">Citations dans le temps</h3>
          <p className="text-xs text-gray-500 mb-6">Nombre de citations par jour et par moteur IA</p>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={result.timeSeries} margin={{ top: 5, right: 10, left: -10, bottom: 5 }}>
                <defs>
                  <linearGradient id="colorChatgpt" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#10b981" stopOpacity={0.3} />
                    <stop offset="95%" stopColor="#10b981" stopOpacity={0} />
                  </linearGradient>
                  <linearGradient id="colorClaude" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#a855f7" stopOpacity={0.3} />
                    <stop offset="95%" stopColor="#a855f7" stopOpacity={0} />
                  </linearGradient>
                  <linearGradient id="colorPerplexity" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.3} />
                    <stop offset="95%" stopColor="#3b82f6" stopOpacity={0} />
                  </linearGradient>
                  <linearGradient id="colorGemini" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#f59e0b" stopOpacity={0.3} />
                    <stop offset="95%" stopColor="#f59e0b" stopOpacity={0} />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />
                <XAxis
                  dataKey="date"
                  tick={{ fill: '#6b7280', fontSize: 11 }}
                  axisLine={{ stroke: 'rgba(255,255,255,0.06)' }}
                  tickLine={false}
                  tickFormatter={(v) => {
                    const d = new Date(v);
                    return `${d.getDate()}/${d.getMonth() + 1}`;
                  }}
                />
                <YAxis
                  tick={{ fill: '#6b7280', fontSize: 11 }}
                  axisLine={false}
                  tickLine={false}
                  allowDecimals={false}
                />
                <Tooltip content={<CustomTooltip />} />
                <Legend
                  wrapperStyle={{ fontSize: '12px', paddingTop: '12px' }}
                  iconType="circle"
                  iconSize={8}
                />
                <Area type="monotone" dataKey="chatgpt" name="ChatGPT" stroke="#10b981" fill="url(#colorChatgpt)" strokeWidth={2} />
                <Area type="monotone" dataKey="claude" name="Claude" stroke="#a855f7" fill="url(#colorClaude)" strokeWidth={2} />
                <Area type="monotone" dataKey="perplexity" name="Perplexity" stroke="#3b82f6" fill="url(#colorPerplexity)" strokeWidth={2} />
                <Area type="monotone" dataKey="gemini" name="Gemini" stroke="#f59e0b" fill="url(#colorGemini)" strokeWidth={2} />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Horizontal Bar Chart - Distribution by engine */}
        <div className="ninja-card p-6">
          <h3 className="text-lg font-bold text-white mb-1">Distribution par moteur</h3>
          <p className="text-xs text-gray-500 mb-6">Repartition des citations</p>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart
                layout="vertical"
                data={result.engineResults.map(e => ({
                  engine: e.engine,
                  citations: e.totalCitations,
                  sov: e.shareOfVoice,
                }))}
                margin={{ top: 5, right: 10, left: 10, bottom: 5 }}
              >
                <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" horizontal={false} />
                <XAxis type="number" tick={{ fill: '#6b7280', fontSize: 11 }} axisLine={false} tickLine={false} />
                <YAxis type="category" dataKey="engine" tick={{ fill: '#9ca3af', fontSize: 12, fontWeight: 500 }} axisLine={false} tickLine={false} width={80} />
                <Tooltip content={<CustomTooltip />} />
                <Bar dataKey="citations" name="Citations" radius={[0, 6, 6, 0]} barSize={24}>
                  {result.engineResults.map((entry) => (
                    <Cell key={entry.engine} fill={ENGINE_COLORS[entry.engine]} fillOpacity={0.8} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* ── Engine Detail Cards ── */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        {result.engineResults.map((engine) => (
          <div key={engine.engine} className="ninja-card p-5">
            <div className="flex items-center justify-between mb-4">
              <span className={`text-sm font-bold px-2.5 py-1 rounded-lg border ${ENGINE_BG[engine.engine]}`}>
                {engine.engine}
              </span>
              <span className={`text-xs font-medium flex items-center gap-1 ${engine.trend >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                {engine.trend >= 0 ? <TrendingUp size={10} /> : <TrendingDown size={10} />}
                {engine.trend >= 0 ? '+' : ''}{engine.trend}%
              </span>
            </div>
            <div className="space-y-3">
              <div className="flex justify-between items-center">
                <span className="text-xs text-gray-500">Citations</span>
                <span className="text-sm font-bold text-white">{engine.totalCitations}</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-xs text-gray-500">Part de voix</span>
                <span className="text-sm font-bold text-white">{engine.shareOfVoice}%</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-xs text-gray-500">Position moy.</span>
                <span className="text-sm font-bold text-white">#{engine.avgPosition}</span>
              </div>
              <div className="pt-2 border-t border-white/[0.06]">
                <span className="text-xs text-gray-500 block mb-2">Sentiment</span>
                <div className="flex gap-1">
                  <div className="bg-emerald-500/30 rounded-full h-1.5" style={{ width: `${engine.sentiment.positive}%` }} />
                  <div className="bg-gray-500/30 rounded-full h-1.5" style={{ width: `${engine.sentiment.neutral}%` }} />
                  <div className="bg-red-500/30 rounded-full h-1.5" style={{ width: `${engine.sentiment.negative}%` }} />
                </div>
                <div className="flex justify-between mt-1.5">
                  <span className="text-[10px] text-emerald-400">{engine.sentiment.positive}%</span>
                  <span className="text-[10px] text-gray-500">{engine.sentiment.neutral}%</span>
                  <span className="text-[10px] text-red-400">{engine.sentiment.negative}%</span>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* ── Citations Table ── */}
      <div className="ninja-card p-6 mb-8">
        <div className="flex items-center justify-between mb-6">
          <div>
            <h3 className="text-lg font-bold text-white">Citations recentes</h3>
            <p className="text-xs text-gray-500 mt-0.5">{result.citations.length} citations detectees</p>
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b border-white/[0.06]">
                <th className="text-left text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Moteur</th>
                <th className="text-left text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Requete</th>
                <th className="text-center text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Position</th>
                <th className="text-left text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Date</th>
                <th className="text-center text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Sentiment</th>
                <th className="text-center text-xs font-medium text-gray-500 uppercase tracking-wider pb-3">Confiance</th>
              </tr>
            </thead>
            <tbody>
              {result.citations.slice(0, 15).map((citation) => {
                const sentCfg = SENTIMENT_CONFIG[citation.sentiment];
                const SentIcon = sentCfg.icon;
                return (
                  <tr key={citation.id} className="border-b border-white/[0.03] hover:bg-white/[0.02] transition-colors">
                    <td className="py-3.5 pr-4">
                      <span className={`text-xs font-medium px-2 py-1 rounded-md border ${ENGINE_BG[citation.engine]}`}>
                        {citation.engine}
                      </span>
                    </td>
                    <td className="py-3.5 pr-4">
                      <div className="max-w-xs">
                        <p className="text-sm text-gray-200 truncate">{citation.query}</p>
                        <p className="text-xs text-gray-600 truncate mt-0.5">{citation.snippet}</p>
                      </div>
                    </td>
                    <td className="py-3.5 pr-4 text-center">
                      <span className={`text-sm font-bold ${citation.position <= 2 ? 'text-emerald-400' : citation.position <= 4 ? 'text-amber-400' : 'text-gray-400'}`}>
                        #{citation.position}
                      </span>
                    </td>
                    <td className="py-3.5 pr-4">
                      <span className="text-xs text-gray-400">{new Date(citation.date).toLocaleDateString('fr-FR')}</span>
                    </td>
                    <td className="py-3.5 pr-4 text-center">
                      <span className={`inline-flex items-center gap-1 text-xs px-2 py-1 rounded-md ${sentCfg.bg} ${sentCfg.color}`}>
                        <SentIcon size={10} />
                        {sentCfg.label}
                      </span>
                    </td>
                    <td className="py-3.5 text-center">
                      <span className="text-xs text-gray-400">{citation.confidence}%</span>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* ── Competitor Comparison ── */}
      <div className="ninja-card p-6 mb-8">
        <div className="flex items-center justify-between mb-6">
          <div>
            <h3 className="text-lg font-bold text-white">Comparaison concurrentielle</h3>
            <p className="text-xs text-gray-500 mt-0.5">Votre marque vs les concurrents detectes</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
          {/* Your brand card */}
          <div className="p-4 rounded-xl bg-gradient-to-br from-purple-500/10 to-violet-600/10 border border-purple-500/20">
            <div className="flex items-center gap-2 mb-3">
              <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-purple-500 to-violet-600 flex items-center justify-center">
                <Sparkles size={14} className="text-white" />
              </div>
              <div>
                <p className="text-sm font-bold text-white truncate">{result.brandName}</p>
                <p className="text-[10px] text-purple-400">Votre marque</p>
              </div>
            </div>
            <div className="space-y-2">
              <div className="flex justify-between">
                <span className="text-xs text-gray-500">Citations</span>
                <span className="text-xs font-bold text-white">{result.totalCitations}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-xs text-gray-500">SoV</span>
                <span className="text-xs font-bold text-purple-400">{result.shareOfVoice}%</span>
              </div>
              <div className="flex justify-between">
                <span className="text-xs text-gray-500">Tendance</span>
                <span className={`text-xs font-bold ${result.trend >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                  {result.trend >= 0 ? '+' : ''}{result.trend}%
                </span>
              </div>
            </div>
          </div>

          {/* Competitor cards */}
          {result.competitors.map((comp) => (
            <div key={comp.name} className="p-4 rounded-xl bg-white/[0.02] border border-white/[0.06] hover:bg-white/[0.04] transition-colors">
              <div className="flex items-center gap-2 mb-3">
                <div className="w-8 h-8 rounded-lg bg-white/[0.06] flex items-center justify-center">
                  <span className="text-xs font-bold text-gray-400">{comp.name.charAt(0)}</span>
                </div>
                <div>
                  <p className="text-sm font-bold text-gray-200 truncate">{comp.name}</p>
                  <span className={`text-[10px] px-1.5 py-0.5 rounded border ${ENGINE_BG[comp.dominantEngine]}`}>
                    {comp.dominantEngine}
                  </span>
                </div>
              </div>
              <div className="space-y-2">
                <div className="flex justify-between">
                  <span className="text-xs text-gray-500">Citations</span>
                  <span className="text-xs font-bold text-gray-300">{comp.totalCitations}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-xs text-gray-500">SoV</span>
                  <span className="text-xs font-bold text-gray-300">{comp.shareOfVoice}%</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-xs text-gray-500">Tendance</span>
                  <span className={`text-xs font-bold ${comp.trend >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                    {comp.trend >= 0 ? '+' : ''}{comp.trend}%
                  </span>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* ── Summary & Recommendations ── */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
        {/* Summary */}
        <div className="ninja-card p-6">
          <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
            <BarChart3 size={18} className="text-purple-400" />
            Resume de l'analyse
          </h3>
          <p className="text-sm text-gray-400 leading-relaxed">{result.summary}</p>
        </div>

        {/* Recommendations */}
        <div className="ninja-card p-6">
          <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
            <Sparkles size={18} className="text-purple-400" />
            Recommandations
          </h3>
          <div className="space-y-3">
            {result.recommendations.map((rec, i) => (
              <div key={i} className="flex items-start gap-3">
                <div className="w-6 h-6 rounded-full bg-purple-500/10 border border-purple-500/20 flex items-center justify-center shrink-0 mt-0.5">
                  <span className="text-xs font-bold text-purple-400">{i + 1}</span>
                </div>
                <p className="text-sm text-gray-400 leading-relaxed">{rec}</p>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ── CTA to other tools ── */}
      <div className="ninja-card p-6 bg-gradient-to-r from-purple-500/5 to-violet-600/5 border-purple-500/10">
        <div className="flex flex-col md:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-4">
            <div className="p-3 rounded-xl bg-purple-500/10">
              <Zap size={20} className="text-purple-400" />
            </div>
            <div>
              <h3 className="text-base font-bold text-white">Ameliorez votre visibilite IA</h3>
              <p className="text-sm text-gray-500">Utilisez nos outils generatifs pour optimiser votre citabilite</p>
            </div>
          </div>
          <button
            onClick={() => onNavigate('generative-tools')}
            className="flex items-center gap-2 px-5 py-2.5 bg-gradient-to-r from-purple-600 to-violet-600 hover:from-purple-500 hover:to-violet-500 text-white text-sm font-medium rounded-xl transition-all shadow-lg shadow-purple-900/30 whitespace-nowrap"
          >
            Voir les outils <ArrowRight size={14} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default AiMonitoring;
"}

{"content":"import React, { useState, useEffect } from 'react';
import { User } from '../types';
import {
  User as UserIcon, Mail, Key, Bell, LogOut, Fuel, Check, Copy, AlertTriangle,
  Droplet, Database, CreditCard, ShieldCheck, LayoutList, History, FileText,
  Download, Loader2, Sparkles, FolderOpen, TrendingUp, Zap, ArrowUpRight,
  Palette, Eye, Globe, Lock
} from 'lucide-react';
import jsPDF from 'jspdf';
import StripeCheckout from '../components/StripeCheckout';

interface AccountProps {
  user: User | null;
  onLogout: () => void;
  onNavigate: (view: any) => void;
  onUpgrade: (plan: 'free' | 'pro' | 'enterprise') => void;
  projectCount: number;
  maxProjects: number;
  initialTab?: 'profile' | 'subscription' | 'billing' | 'whitelabel';
}

const Account: React.FC<AccountProps> = ({ user, onLogout, onNavigate, onUpgrade, projectCount, maxProjects, initialTab = 'profile' }) => {
  const [activeTab, setActiveTab] = useState<'profile' | 'subscription' | 'billing' | 'whitelabel'>(initialTab);
  const [apiKeyCopied, setApiKeyCopied] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [upgradeModal, setUpgradeModal] = useState<{ planId: string; planName: string; newPrice: number } | null>(null);
  const [paymentStep, setPaymentStep] = useState<'recap' | 'payment' | 'success'>('recap');
  const [paidAmount, setPaidAmount] = useState(0);
  const [paymentHistory, setPaymentHistory] = useState([
    { id: 'INV-2024-003', date: '01/03/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
    { id: 'INV-2024-002', date: '01/02/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
    { id: 'INV-2024-001', date: '15/01/2024', amount: 49.00, desc: 'Pack GTO Gas (La Pompe)', status: 'Payé' },
  ]);

  // White Label state
  const [whiteLabel, setWhiteLabel] = useState(() => {
    try {
      const saved = localStorage.getItem('citedby-whitelabel');
      return saved ? JSON.parse(saved) : { logoUrl: '', agencyName: '', primaryColor: '#a855f7', secondaryColor: '#7c3aed' };
    } catch { return { logoUrl: '', agencyName: '', primaryColor: '#a855f7', secondaryColor: '#7c3aed' }; }
  });
  const [wlSaved, setWlSaved] = useState(false);

  const handleSaveWhiteLabel = () => {
    localStorage.setItem('citedby-whitelabel', JSON.stringify(whiteLabel));
    setWlSaved(true);
    setTimeout(() => setWlSaved(false), 2000);
  };

  const generateBrandedPdf = () => {
    const doc = new jsPDF();
    doc.setFillColor(whiteLabel.primaryColor || '#a855f7');
    doc.rect(0, 0, 210, 40, 'F');
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(22);
    doc.setFont('helvetica', 'bold');
    doc.text(whiteLabel.agencyName || 'Mon Agence', 20, 25);
    doc.setFontSize(10);
    doc.text('Rapport AEO — Marque Blanche', 20, 33);
    doc.setTextColor(60, 60, 60);
    doc.setFontSize(12);
    doc.text('Rapport de Visibilité IA', 20, 55);
    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`Généré le ${new Date().toLocaleDateString('fr-FR')}`, 20, 63);
    doc.text(`Client : ${user?.name || 'N/A'}`, 20, 70);
    doc.setFontSize(14);
    doc.setFont('helvetica', 'bold');
    doc.text('Score Global AEO', 20, 90);
    doc.setFontSize(36);
    doc.setTextColor(whiteLabel.primaryColor || '#a855f7');
    doc.text('78/100', 20, 110);
    doc.setTextColor(100, 100, 100);
    doc.setFontSize(9);
    doc.text(`Powered by ${whiteLabel.agencyName || 'CitedBy.ai'}`, 20, 280);
    doc.save(`Rapport_${whiteLabel.agencyName || 'AEO'}_${Date.now()}.pdf`);
  };

  useEffect(() => {
    setActiveTab(initialTab);
  }, [initialTab]);

  if (!user) return null;

  // ── Helpers ──

  const handleCopyApiKey = () => {
    navigator.clipboard.writeText(`cb_pk_live_${user.id.substring(0, 8)}_${Math.random().toString(36).substr(2, 9)}`);
    setApiKeyCopied(true);
    setTimeout(() => setApiKeyCopied(false), 2000);
  };

  const getPlanDetails = (plan: string) => {
    switch (plan) {
      case 'enterprise':
        return { name: 'Agency', marketingName: 'La Citerne', icon: <Database size={14} className="fill-current" />, style: 'bg-purple-500/10 text-purple-500 border-white/[0.1] shadow-[0_0_15px_rgba(168,85,247,0.1)]' };
      case 'pro':
        return { name: 'Pro', marketingName: 'La Pompe', icon: <Fuel size={14} className="fill-current" />, style: 'bg-purple-500/10 text-purple-400 border-primary/20 shadow-[0_0_15px_rgba(16,185,129,0.1)]' };
      default:
        return { name: 'Starter', marketingName: 'Le Jerrican', icon: <Droplet size={14} />, style: 'bg-white/[0.04] text-gray-300 border-white/[0.08]' };
    }
  };

  const planDetails = getPlanDetails(user.plan);
  const projectPercentage = maxProjects >= 1000 ? 15 : Math.min((projectCount / maxProjects) * 100, 100);
  const isAtLimit = projectCount >= maxProjects && maxProjects < 1000;

  // ── Pricing data ──

  const plans = [
    {
      id: 'free', name: 'Starter', price: 29, period: '/mois',
      icon: <Droplet size={24} />, current: user.plan === 'free',
      features: ['1 Projet Actif / mois', 'Audit manuel', 'Support communauté'],
      cta: 'Plan Actuel',
    },
    {
      id: 'pro', name: 'Pro', price: 89, period: '/mois', popular: true,
      icon: <Fuel size={24} />, current: user.plan === 'pro',
      features: ['Indexation IA', '3 Projets Actifs / mois', 'Monitoring Continu', 'Support Prioritaire', 'API Access (Beta)', 'Rapports PDF marque blanche'],
      cta: 'Passer Pro',
    },
    {
      id: 'enterprise', name: 'Agency', price: 299, period: '/mois',
      icon: <Database size={24} />, current: user.plan === 'enterprise',
      features: ['Indexation IA', 'Projets illimités', 'Dedicated Account Manager', 'API Full Access', 'SSO & Sécurité avancée', 'Formation AEO équipe'],
      cta: 'Passer Agency',
    },
  ];

  // Prix du plan actuel de l'utilisateur
  const currentPlanPrice = user.plan === 'enterprise' ? 299 : user.plan === 'pro' ? 89 : 29;

  const handleUpgradeClick = (planId: string) => {
    const targetPlan = plans.find(p => p.id === planId);
    if (!targetPlan || targetPlan.current) return;
    setUpgradeModal({ planId, planName: targetPlan.name, newPrice: targetPlan.price });
    setPaymentStep('payment');
  };

  const handleProcessPayment = () => {
    if (!upgradeModal) return;
    setIsProcessing(true);
    setTimeout(() => {
      const amountPaid = upgradeModal.newPrice - currentPlanPrice;
      const now = new Date();
      const dateStr = now.toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' });
      const invoiceNum = `INV-${now.getFullYear()}-${String(paymentHistory.length + 1).padStart(3, '0')}`;
      const newInvoice = {
        id: invoiceNum,
        date: dateStr,
        amount: amountPaid,
        desc: `Upgrade ${planDetails.name} → ${upgradeModal.planName} (Prorata)`,
        status: 'Payé',
      };
      setPaymentHistory(prev => [newInvoice, ...prev]);
      setPaidAmount(amountPaid);
      onUpgrade(upgradeModal.planId as any);
      setIsProcessing(false);
      setPaymentStep('success');
    }, 2500);
  };

  const handleCloseUpgradeModal = () => {
    setUpgradeModal(null);
    setPaymentStep('recap');
    setPaidAmount(0);
  };

  // ── Invoice PDF ──

  const generateInvoice = (payment: { id: string; date: string; amount: number; desc: string; status: string }) => {
    const doc = new jsPDF();
    doc.setFontSize(22);
    doc.setFont('helvetica', 'bold');
    doc.text('CitedBy.ai', 20, 20);
    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`Facture N° ${payment.id}`, 20, 30);
    doc.text(`Date : ${payment.date}`, 20, 35);
    doc.text('Facturé à :', 140, 30);
    doc.setFont('helvetica', 'bold');
    doc.text(user.name || 'Client', 140, 35);
    doc.setFont('helvetica', 'normal');
    doc.text(user.email || '', 140, 40);
    doc.line(20, 55, 190, 55);
    doc.setFont('helvetica', 'bold');
    doc.text('Description', 20, 62);
    doc.text('Montant HT', 160, 62);
    doc.line(20, 66, 190, 66);
    const priceHT = (payment.amount / 1.2).toFixed(2);
    const tva = (payment.amount - parseFloat(priceHT)).toFixed(2);
    doc.setFont('helvetica', 'normal');
    doc.text(payment.desc, 20, 75);
    doc.text(`${priceHT} €`, 160, 75);
    doc.line(20, 90, 190, 90);
    doc.text('Sous-total HT :', 130, 100);
    doc.text(`${priceHT} €`, 160, 100);
    doc.text('TVA (20%) :', 130, 107);
    doc.text(`${tva} €`, 160, 107);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(12);
    doc.text('Total TTC :', 130, 117);
    doc.text(`${payment.amount.toFixed(2)} €`, 160, 117);
    doc.setFontSize(8);
    doc.setFont('helvetica', 'italic');
    doc.text('Merci de votre confiance. Paiement effectué par CB.', 20, 140);
    doc.save(`Facture_${payment.id}.pdf`);
  };

  // ── Render ──

  return (
    <div className="w-full px-4 py-10 animate-in fade-in duration-500 min-h-screen">

      {/* ── STEP 2 : PLEINE PAGE DE PAIEMENT (comme Recharge.tsx) ── */}
      {upgradeModal && paymentStep === 'payment' && (
        <div className="animate-in fade-in slide-in-from-right duration-500">
          <StripeCheckout
            mode="subscription"
            productName={`Plan ${upgradeModal.planName}`}
            productDescription={`Upgrade ${planDetails.name} → ${upgradeModal.planName}`}
            amount={upgradeModal.newPrice - currentPlanPrice}
            amountDetails={[
              { label: `Nouveau plan (${upgradeModal.planName})`, value: `${upgradeModal.newPrice.toFixed(2)} €` },
              { label: `Crédit plan ${planDetails.name}`, value: `- ${currentPlanPrice.toFixed(2)} €` },
              { label: 'À payer aujourd\'hui', value: `${(upgradeModal.newPrice - currentPlanPrice).toFixed(2)} €`, highlight: true, separator: true },
            ]}
            userEmail={user.email}
            onConfirm={handleProcessPayment}
            onBack={() => setPaymentStep('recap')}
            isProcessing={isProcessing}
          />
        </div>
      )}

      {/* Contenu principal — masqué pendant le paiement */}
      {!(upgradeModal && paymentStep === 'payment') && (<>

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 bg-gradient-to-br from-purple-500 to-violet-600 rounded-2xl flex items-center justify-center text-white font-bold text-2xl shadow-lg shadow-purple-500/20 border-2 border-black">
            {user.name.charAt(0).toUpperCase()}
          </div>
          <div>
            <h1 className="text-3xl font-sans font-bold text-white">Compte & Plan</h1>
            <p className="text-gray-500 text-sm">Profil, abonnement, facturation</p>
          </div>
        </div>
        <button
          onClick={onLogout}
          className="flex items-center gap-2 px-4 py-2 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/20 rounded-full transition-colors text-sm font-medium"
        >
          <LogOut size={16} /> Déconnexion
        </button>
      </div>

      {/* Tabs */}
      <div className="flex justify-center mb-10">
        <div className="inline-flex bg-white/[0.04] p-1.5 rounded-2xl border border-white/[0.08] flex-wrap justify-center gap-1">
          {([
            { key: 'profile', icon: UserIcon, label: 'Profil' },
            { key: 'subscription', icon: ShieldCheck, label: 'Abonnement & Projets' },
            { key: 'billing', icon: CreditCard, label: 'Facturation' },
            ...(user.plan === 'enterprise' ? [{ key: 'whitelabel' as const, icon: Palette, label: 'White Label' }] : []),
          ] as const).map(tab => (
            <button
              key={tab.key}
              onClick={() => setActiveTab(tab.key)}
              className={`px-5 py-2.5 rounded-2xl text-sm font-bold transition-all flex items-center gap-2 ${
                activeTab === tab.key
                  ? 'bg-gradient-to-r from-purple-500 to-violet-600 text-white shadow-lg'
                  : 'text-gray-500 hover:text-white'
              }`}
            >
              <tab.icon size={16} /> {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* ═══════════════════════════════════════════════
          TAB 1 : PROFIL
          ═══════════════════════════════════════════════ */}
      {activeTab === 'profile' && (
        <div className="animate-in fade-in duration-300 grid lg:grid-cols-3 gap-8">

          {/* Left: Profile Card + GTO Balance */}
          <div className="space-y-6">
            {/* Profile summary */}
            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] text-center relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-24 bg-gradient-to-b from-white/5 to-transparent"></div>
              <div className="relative">
                <div className="w-24 h-24 mx-auto bg-gradient-to-br from-purple-500 to-violet-600 rounded-full flex items-center justify-center text-white font-bold text-4xl shadow-xl shadow-purple-500/20 mb-4 border-4 border-black">
                  {user.name.charAt(0).toUpperCase()}
                </div>
                <h2 className="text-xl font-bold text-white">{user.name}</h2>
                <p className="text-sm text-gray-500 mb-4">{user.email}</p>
                <div className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full border text-xs font-bold uppercase tracking-wide ${planDetails.style}`}>
                  {planDetails.icon}
                  {planDetails.marketingName}
                </div>
              </div>
            </div>

            {/* GTO Gas balance */}
            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] relative overflow-hidden">
              <div className="flex justify-between items-start mb-4">
                <div className="p-3 bg-purple-500/10 rounded-2xl text-purple-400">
                  <Fuel size={24} />
                </div>
                <button
                  onClick={() => onNavigate('recharge')}
                  className="text-xs bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold px-3 py-1.5 rounded-full hover:brightness-110 transition-all"
                >
                  Recharger
                </button>
              </div>
              <p className="text-sm text-gray-500 mb-1">Solde GTO Gas</p>
              <div className="text-4xl font-bold text-white mb-2">{user.credits}</div>
              <div className="w-full bg-white/[0.08] h-1.5 rounded-full overflow-hidden">
                <div className="bg-purple-500 h-full rounded-full transition-all" style={{ width: `${Math.min((user.credits / 500) * 100, 100)}%` }}></div>
              </div>
              <p className="text-xs text-gray-500 mt-2">~{Math.floor(user.credits / 10)} audits restants</p>
            </div>
          </div>

          {/* Right: Settings */}
          <div className="lg:col-span-2 space-y-8">
            {/* API Keys */}
            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
              <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                <Key size={20} className="text-purple-400" /> Clés API & Intégrations
              </h3>
              <div className="bg-black/40 border border-white/[0.08] rounded-2xl p-4 flex items-center justify-between gap-4">
                <div className="flex-1 overflow-hidden">
                  <p className="text-xs text-gray-500 mb-1 uppercase tracking-wider">Clé Publique</p>
                  <code className="text-sm text-purple-300 font-mono block truncate">cb_pk_live_{user.id.substring(0, 8)}...</code>
                </div>
