                          <div className="h-full rounded-full transition-all" style={{ width: `${[72, 85, 60, 90][i]}%`, background: `linear-gradient(90deg, ${whiteLabel.primaryColor}, ${whiteLabel.secondaryColor})` }} />
                        </div>
                        <span className="text-[10px] text-gray-400 w-6 text-right">{[72, 85, 60, 90][i]}</span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              {/* Custom domain - Coming Soon */}
              <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] opacity-60">
                <div className="flex items-center gap-3">
                  <div className="p-2.5 bg-purple-500/10 rounded-xl">
                    <Globe size={20} className="text-purple-400" />
                  </div>
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      <h4 className="font-bold text-white text-sm">Domaine personnalisé</h4>
                      <span className="text-[10px] bg-amber-500/10 text-amber-400 px-2 py-0.5 rounded-full border border-amber-500/20">Coming Soon</span>
                    </div>
                    <p className="text-xs text-gray-500 mt-1">app.votre-agence.com — Accès client sous votre propre domaine</p>
                  </div>
                  <Lock size={16} className="text-gray-600" />
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      </>)}

      {/* MODAL SUCCÈS */}
      {upgradeModal && paymentStep === 'success' && (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4" style={{ left: 0, top: 0, width: '100vw', height: '100vh' }}>
          <div className="absolute inset-0 bg-black/70 backdrop-blur-sm" onClick={() => !isProcessing && handleCloseUpgradeModal()} />
          <div className="relative z-10 bg-[#111111] border border-purple-500/20 rounded-2xl w-full max-w-lg shadow-2xl shadow-purple-500/10 mx-auto">
            {paymentStep === 'success' && (
              <div className="p-8 text-center space-y-5">
                <div className="w-20 h-20 mx-auto rounded-full bg-green-500/10 border-2 border-green-500/20 flex items-center justify-center">
                  <Check size={40} className="text-green-400" />
                </div>
                <div>
                  <h2 className="text-xl font-bold text-white mb-2">Paiement confirmé !</h2>
                  <p className="text-sm text-gray-400">
                    Vous êtes maintenant sur le plan <span className="text-purple-400 font-bold">{upgradeModal.planName}</span>.
                  </p>
                </div>
                <div className="bg-white/[0.03] rounded-xl border border-white/[0.06] p-4 space-y-2 text-left">
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-400">Montant débité</span>
                    <span className="text-white font-bold">{paidAmount.toFixed(2)} €</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-400">Moyen de paiement</span>
                    <span className="text-white">•••• 4242</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-400">Prochain renouvellement</span>
                    <span className="text-white">{upgradeModal.newPrice}€/mois</span>
                  </div>
                </div>
                <div className="flex gap-3 pt-2">
                  <button onClick={() => { handleCloseUpgradeModal(); setActiveTab('subscription'); }}
                    className="flex-1 px-4 py-2.5 text-sm text-gray-400 hover:text-white border border-white/[0.08] rounded-xl transition-colors">
                    Mon abonnement
                  </button>
                  <button onClick={() => { handleCloseUpgradeModal(); setActiveTab('billing'); }}
                    className="flex-1 px-4 py-2.5 bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-all shadow-lg shadow-purple-500/20 text-sm">
                    <FileText size={16} /> Voir ma facture
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Account;
"}

{"content":"import React, { useState, useEffect, useRef } from 'react';

// Animated counter hook
const useCountUp = (target: number, duration = 1200) => {
  const [count, setCount] = useState(0);
  const ref = useRef<HTMLDivElement>(null);
  useEffect(() => {
    const observer = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) {
        let start = 0;
        const startTime = performance.now();
        const step = (now: number) => {
          const progress = Math.min((now - startTime) / duration, 1);
          const eased = 1 - Math.pow(1 - progress, 3); // ease-out cubic
          setCount(Math.round(eased * target));
          if (progress < 1) requestAnimationFrame(step);
        };
        requestAnimationFrame(step);
        observer.disconnect();
      }
    }, { threshold: 0.3 });
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, [target, duration]);
  return { count, ref };
};
import {
  Plus,
  FileText,
  Users,
  MessageSquare,
  Bell,
  ShoppingBag,
  Settings,
  Search,
  ChevronLeft,
  ChevronRight,
  TrendingUp,
  AlertTriangle,
  Fuel,
  Share2,
  BarChart3,
  Target,
  ArrowUpRight,
  ArrowDownRight
} from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';
import { AnalysisResult } from '../types';

interface DashboardProps {
  onBack: () => void;
  history: AnalysisResult[];
  onView: (analysis: AnalysisResult) => void;
  onNavigate: (view: any) => void;
}

type TableRow = {
  url: string;
  score: number;
  citation: string;
  date: string;
  status: string;
  statusClass: string;
  original?: AnalysisResult;
};

const Dashboard: React.FC<DashboardProps> = ({ onBack, history, onView, onNavigate }) => {
  const scoreKpi = useCountUp(78);
  const citationKpi = useCountUp(68);
  const projectsKpi = useCountUp(5, 800);
  const alertsKpi = useCountUp(3, 800);

  // Données de démonstration pour matcher l'image si l'historique est vide
  const demoData: TableRow[] = [
    { url: 'example.com/article-1', score: 85, citation: '78%', date: 'Il y a 2h', status: 'Excellent', statusClass: 'bg-purple-400/20 text-purple-300' },
    { url: 'myblog.com/guide-seo', score: 72, citation: '65%', date: 'Il y a 5h', status: 'Bon', statusClass: 'bg-primary/20 text-primary' },
    { url: 'tech-news.io/ai-trends', score: 88, citation: '82%', date: 'Hier', status: 'Excellent', statusClass: 'bg-purple-400/20 text-purple-300' },
    { url: 'startup.co/blog/growth', score: 58, citation: '42%', date: 'Hier', status: 'Moyen', statusClass: 'bg-blue-500/20 text-blue-400' },
    { url: 'ecommerce.shop/products', score: 91, citation: '88%', date: 'Il y a 2 jours', status: 'Excellent', statusClass: 'bg-purple-400/20 text-purple-300' },
  ];

  const tableData: TableRow[] = history.length > 0 ? history.map(h => ({
    url: new URL(h.url).hostname + new URL(h.url).pathname,
    score: h.globalScore,
    citation: `${h.aiCitation.probability}%`,
    date: new Date(h.timestamp).toLocaleDateString(),
    status: h.globalScore >= 80 ? 'Excellent' : h.globalScore >= 60 ? 'Bon' : 'Moyen',
    statusClass: h.globalScore >= 80 ? 'bg-purple-400/20 text-purple-300' : h.globalScore >= 60 ? 'bg-primary/20 text-primary' : 'bg-blue-500/20 text-blue-400',
    original: h
  })) : demoData;

  const chartData = [
    { day: 'Lun', score: 72, citations: 45 },
    { day: 'Mar', score: 75, citations: 52 },
    { day: 'Mer', score: 68, citations: 48 },
    { day: 'Jeu', score: 82, citations: 61 },
    { day: 'Ven', score: 79, citations: 58 },
    { day: 'Sam', score: 85, citations: 64 },
    { day: 'Dim', score: 88, citations: 70 },
  ];

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload?.length) {
      return (
        <div className="bg-[#1a1d21] border border-white/10 rounded-xl p-3 shadow-xl">
          <p className="text-gray-400 text-xs mb-1">{label}</p>
          {payload.map((entry: any, i: number) => (
            <p key={i} className="text-sm font-bold" style={{ color: entry.color }}>
              {entry.name === 'score' ? 'Score' : 'Citations'}: {entry.value}{entry.name === 'citations' ? '%' : '/100'}
            </p>
          ))}
        </div>
      );
    }
    return null;
  };

  const ActionCard = ({ icon: Icon, label, color, view }: { icon: any, label: string, color: string, view: string }) => (
    <button 
      onClick={() => onNavigate(view)}
      className="ninja-card p-6 flex flex-col items-center justify-center gap-3 transition-all hover:-translate-y-1 group w-full"
    >
      <Icon size={28} className={color} />
      <span className="text-sm font-semibold text-gray-300 group-hover:text-white">{label}</span>
    </button>
  );

  return (
    <div className="w-full px-6 py-8">

      {/* Header Interne Dashboard */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div className="flex items-center gap-4">
          <h1 className="text-3xl font-bold font-sans text-white">Dashboard <span className="gradient-text">Pro</span></h1>
        </div>

        <div className="flex items-center gap-4 w-full md:w-auto">
          <button
            onClick={() => document.dispatchEvent(new KeyboardEvent('keydown', { key: 'k', ctrlKey: true, bubbles: true }))}
            className="relative flex items-center gap-2 bg-[#111111] border border-white/[0.08] rounded-xl py-2.5 pl-4 pr-3 text-sm text-gray-500 hover:border-purple-500/30 hover:text-gray-400 transition-colors w-full md:w-64 cursor-pointer"
          >
            <Search size={16} />
            <span className="flex-1 text-left">Rechercher...</span>
            <kbd className="hidden sm:flex items-center gap-0.5 px-1.5 py-0.5 text-[10px] text-gray-600 bg-white/[0.04] border border-white/[0.08] rounded-md font-mono">⌘K</kbd>
          </button>
          <button 
            onClick={() => onNavigate('analyze')}
            className="btn-gradient text-white font-bold px-6 py-2.5 rounded-full flex items-center gap-2 transition-colors whitespace-nowrap"
          >
            <Plus size={18} /> Nouvelle analyse
          </button>
        </div>
      </div>

      {/* Action Cards Row */}
      <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-8 gap-4 mb-8">
        <ActionCard icon={Fuel} label="Gas Station" color="text-primary" view="recharge" />
        <ActionCard icon={FileText} label="Rapport" color="text-blue-400" view="history" />
        <ActionCard icon={Users} label="Client" color="text-purple-400" view="clients" />
        <ActionCard icon={Share2} label="Affiliation" color="text-pink-400" view="affiliation" />
        <ActionCard icon={MessageSquare} label="Message" color="text-white" view="messages" />
        <ActionCard icon={Bell} label="Alertes" color="text-red-400" view="alerts" />
        <ActionCard icon={ShoppingBag} label="Store" color="text-indigo-400" view="directory" />
        <ActionCard icon={Settings} label="Paramètres" color="text-gray-400" view="account" />
      </div>

      {/* KPI Summary Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
        {/* Score Moyen */}
        <div className="ninja-card p-5 relative group cursor-default" ref={scoreKpi.ref}>
          <div className="flex items-center gap-3 mb-3">
            <div className="w-10 h-10 rounded-full bg-purple-500/20 flex items-center justify-center">
              <TrendingUp size={20} className="text-purple-400" />
            </div>
          </div>
          <div className="text-2xl font-bold text-white">{scoreKpi.count}<span className="text-sm text-gray-500 font-normal">/100</span></div>
          <div className="text-sm text-gray-500 mt-1">Score Moyen</div>
          <div className="flex items-center gap-1 mt-2 text-xs text-green-400">
            <ArrowUpRight size={14} />
            <span>+5.2% ce mois</span>
          </div>
          <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-3 py-2 bg-[#1a1d21] border border-white/[0.1] rounded-lg shadow-xl text-xs text-gray-300 whitespace-nowrap opacity-0 pointer-events-none group-hover:opacity-100 transition-opacity duration-200 z-50">
            Moyenne pondérée de tous vos audits AEO
          </div>
        </div>

        {/* Taux Citation IA */}
        <div className="ninja-card p-5 relative group cursor-default" ref={citationKpi.ref}>
          <div className="flex items-center gap-3 mb-3">
            <div className="w-10 h-10 rounded-full bg-green-500/20 flex items-center justify-center">
              <Target size={20} className="text-green-400" />
            </div>
          </div>
          <div className="text-2xl font-bold text-white">{citationKpi.count}<span className="text-sm text-gray-500 font-normal">%</span></div>
          <div className="text-sm text-gray-500 mt-1">Taux Citation IA</div>
          <div className="flex items-center gap-1 mt-2 text-xs text-green-400">
            <ArrowUpRight size={14} />
            <span>+12% ce mois</span>
          </div>
          <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-3 py-2 bg-[#1a1d21] border border-white/[0.1] rounded-lg shadow-xl text-xs text-gray-300 whitespace-nowrap opacity-0 pointer-events-none group-hover:opacity-100 transition-opacity duration-200 z-50">
            Probabilité d'être cité par ChatGPT, Claude, Gemini
          </div>
        </div>

        {/* Projets Actifs */}
        <div className="ninja-card p-5 relative group cursor-default" ref={projectsKpi.ref}>
          <div className="flex items-center gap-3 mb-3">
            <div className="w-10 h-10 rounded-full bg-blue-500/20 flex items-center justify-center">
              <BarChart3 size={20} className="text-blue-400" />
            </div>
          </div>
          <div className="text-2xl font-bold text-white">{projectsKpi.count}</div>
          <div className="text-sm text-gray-500 mt-1">Projets Actifs</div>
          <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-3 py-2 bg-[#1a1d21] border border-white/[0.1] rounded-lg shadow-xl text-xs text-gray-300 whitespace-nowrap opacity-0 pointer-events-none group-hover:opacity-100 transition-opacity duration-200 z-50">
            Nombre de sites monitorés ce mois
          </div>
        </div>

        {/* Alertes Actives */}
        <div className="ninja-card p-5 relative group cursor-default" ref={alertsKpi.ref}>
          <div className="flex items-center gap-3 mb-3">
            <div className="w-10 h-10 rounded-full bg-red-500/20 flex items-center justify-center">
              <AlertTriangle size={20} className="text-red-400" />
            </div>
          </div>
          <div className="text-2xl font-bold text-white">{alertsKpi.count}</div>
          <div className="text-sm text-gray-500 mt-1">Alertes Actives</div>
          <div className="flex items-center gap-1 mt-2 text-xs text-red-400">
            <ArrowDownRight size={14} />
            <span>1 critique</span>
          </div>
          <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-3 py-2 bg-[#1a1d21] border border-white/[0.1] rounded-lg shadow-xl text-xs text-gray-300 whitespace-nowrap opacity-0 pointer-events-none group-hover:opacity-100 transition-opacity duration-200 z-50">
            Alertes de chute de visibilité à traiter
          </div>
        </div>
      </div>

      {/* Main Grid */}
      <div className="grid lg:grid-cols-3 gap-6">

        {/* Table Column (2/3) */}
        <div className="lg:col-span-2 ninja-card p-6">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-xl font-bold font-sans text-white">Dernières <span className="gradient-text">analyses</span></h2>
            <select className="bg-[#111111] border border-white/[0.08] text-gray-300 text-sm rounded-xl px-3 py-1.5 focus:outline-none focus:border-purple-500/50">
              <option>Tous les statuts</option>
              <option>Excellent</option>
              <option>Bon</option>
              <option>Moyen</option>
            </select>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-gray-500 text-sm border-b border-white/[0.06]">
                  <th className="pb-4 font-medium pl-2">URL</th>
                  <th className="pb-4 font-medium">Score</th>
                  <th className="pb-4 font-medium">Citation IA</th>
                  <th className="pb-4 font-medium">Date</th>
                  <th className="pb-4 font-medium">Statut</th>
                </tr>
              </thead>
              <tbody className="text-sm">
                {tableData.map((row, idx) => (
                  <tr 
                    key={idx} 
                    className="border-b border-white/[0.06] last:border-0 hover:bg-white/5 transition-colors cursor-pointer group"
                    onClick={() => row.original ? onView(row.original) : null}
                  >
                    <td className="py-4 pl-2 font-medium text-gray-200 group-hover:text-white transition-colors">{row.url}</td>
                    <td className="py-4">
                      <span className={row.status === 'Excellent' ? 'text-purple-300 font-bold' : row.status === 'Bon' ? 'text-primary font-bold' : 'text-blue-400 font-bold'}>
                        {row.score}
                      </span>
                      <span className="text-gray-600 text-xs">/100</span>
                    </td>
                    <td className="py-4 text-gray-300">{row.citation}</td>
                    <td className="py-4 text-gray-500">{row.date}</td>
                    <td className="py-4">
                      <span className={`px-3 py-1 rounded-full text-xs font-bold ${row.statusClass}`}>
                        {row.status}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <div className="flex justify-between items-center mt-6 text-sm text-gray-500 pt-4 border-t border-white/[0.06]">
            <div>Affichage 1-5 sur 24 résultats</div>
            <div className="flex items-center gap-2">
              <button className="w-8 h-8 flex items-center justify-center rounded bg-[#111111] hover:bg-white/5 transition-colors"><ChevronLeft size={16} /></button>
              <button className="w-8 h-8 flex items-center justify-center rounded-full btn-gradient text-white font-bold">1</button>
              <button className="w-8 h-8 flex items-center justify-center rounded bg-[#111111] hover:bg-white/5 transition-colors">2</button>
              <button className="w-8 h-8 flex items-center justify-center rounded bg-[#111111] hover:bg-white/5 transition-colors">3</button>
              <button className="w-8 h-8 flex items-center justify-center rounded bg-[#111111] hover:bg-white/5 transition-colors"><ChevronRight size={16} /></button>
            </div>
          </div>
        </div>

        {/* Chart Column (1/3) */}
        <div className="lg:col-span-1 space-y-6">
          <div className="ninja-card p-6 h-full min-h-[300px] flex flex-col">
            <h2 className="text-xl font-bold font-sans text-white mb-6">Évolution des <span className="gradient-text">scores</span></h2>

            <div className="flex-1 w-full min-h-[220px]">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData} margin={{ top: 5, right: 5, left: -20, bottom: 0 }}>
                  <defs>
                    <linearGradient id="gradientScore" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#a855f7" stopOpacity={0.3} />
                      <stop offset="95%" stopColor="#a855f7" stopOpacity={0} />
                    </linearGradient>
                    <linearGradient id="gradientCitations" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#8b5cf6" stopOpacity={0.3} />
                      <stop offset="95%" stopColor="#8b5cf6" stopOpacity={0} />
                    </linearGradient>
                  </defs>
                  <XAxis
                    dataKey="day"
                    axisLine={false}
                    tickLine={false}
                    tick={{ fill: '#6b7280', fontSize: 12 }}
                  />
                  <YAxis
                    axisLine={false}
                    tickLine={false}
                    tick={{ fill: '#6b7280', fontSize: 12 }}
                    domain={[0, 100]}
                  />
                  <Tooltip content={<CustomTooltip />} />
                  <Area
                    type="monotone"
                    dataKey="score"
                    stroke="#a855f7"
                    strokeWidth={2}
                    fill="url(#gradientScore)"
                    name="score"
                  />
                  <Area
                    type="monotone"
                    dataKey="citations"
                    stroke="#8b5cf6"
                    strokeWidth={2}
                    fill="url(#gradientCitations)"
                    name="citations"
                  />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>
        </div>

      </div>
    </div>
  );
};

export default Dashboard;
"}

{"content":"import { Suspense, lazy, useState, useEffect, useRef } from 'react';
import { Navigate, Outlet, Route, Routes, useNavigate } from 'react-router-dom';
