import { AuthProvider, useAuth } from './hooks/useAuth';

import AuthPage from './pages/AuthPage';
import SectorSelectPage from './pages/SectorSelectPage';
const RadarPage = lazy(() => import('./pages/RadarPage'));
const ProspectDetailPage = lazy(() => import('./pages/ProspectDetailPage'));
const PipelinePage = lazy(() => import('./pages/PipelinePage'));
const SourcesPage = lazy(() => import('./pages/SourcesPage'));
const StatsPage = lazy(() => import('./pages/StatsPage'));
const SettingsPage = lazy(() => import('./pages/SettingsPage'));

const LoadingScreen = (): JSX.Element => (
  <div className="flex min-h-screen items-center justify-center bg-leadradar-bg">
    <div className="h-12 w-12 animate-spin rounded-full border-4 border-leadradar-border border-t-leadradar-accent" />
  </div>
);

const ProtectedShell = (): JSX.Element => (
  <AuthGuard>
    <AppLayout>
      <Outlet />
    </AppLayout>
  </AuthGuard>
);

const CommandPalette: React.FC<{ isOpen: boolean; onClose: () => void; onNavigate: (view: string) => void; }> = ({ isOpen, onClose, onNavigate }) => {
  const [query, setQuery] = useState('');
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 100);
      setQuery('');
    }
  }, [isOpen]);

  const commands = [
    { id: 'analyze', label: 'Nouvel Audit AEO', icon: '\u{1F50D}', category: 'Navigation' },
    { id: 'dashboard', label: 'Dashboard Pro', icon: '\u{1F4CA}', category: 'Navigation' },
    { id: 'projects', label: 'Monitoring AEO', icon: '\u{1F4C8}', category: 'Navigation' },
    { id: 'generative-tools', label: 'Outils G\u00e9n\u00e9ratifs', icon: '\u2728', category: 'Outils' },
    { id: 'smc-studio', label: 'SMC Studio', icon: '\u270F\uFE0F', category: 'Outils' },
    { id: 'content-writer', label: 'AI Content Writer', icon: '\u{1F4DD}', category: 'Outils' },
    { id: 'reputation', label: 'R\u00e9putation IA', icon: '\u{1F6E1}\uFE0F', category: 'Outils' },
    { id: 'source-of-truth', label: 'Source of Truth', icon: '\u{1F4C4}', category: 'Outils' },
    { id: 'schema-org', label: 'Schema.org Generator', icon: '\u{1F527}', category: 'Outils' },
    { id: 'robots-txt', label: 'Robots.txt Optimizer', icon: '\u{1F916}', category: 'Outils' },
    { id: 'bot-tracking', label: 'Suivi Bots IA', icon: '\u{1F441}\uFE0F', category: 'Outils' },
    { id: 'blog-optimizer', label: 'Blog Optimiser', icon: '\u{1F4F0}', category: 'Outils' },
    { id: 'directory', label: 'Annuaire Index\u00e9', icon: '\u{1F4DA}', category: 'Navigation' },
    { id: 'recharge', label: 'GTO Gas Station', icon: '\u26FD', category: 'Navigation' },
    { id: 'clients', label: 'Base Clients', icon: '\u{1F465}', category: 'Navigation' },
    { id: 'mission-orders', label: 'Ordres de Mission', icon: '\u{1F4CB}', category: 'Navigation' },
    { id: 'alerts', label: 'Alertes AEO', icon: '\u{1F514}', category: 'Navigation' },
    { id: 'account', label: 'Compte & Plan', icon: '\u{1F464}', category: 'Navigation' },
    { id: 'affiliation', label: 'Programme Partenaire', icon: '\u{1F91D}', category: 'Navigation' },
  ];

  const filtered = query
    ? commands.filter(c => c.label.toLowerCase().includes(query.toLowerCase()))
    : commands;

  const grouped = filtered.reduce((acc, cmd) => {
    if (!acc[cmd.category]) acc[cmd.category] = [];
    acc[cmd.category].push(cmd);
    return acc;
  }, {} as Record<string, typeof commands>);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-start justify-center pt-[20vh]" onClick={onClose}>
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" />
      <div
        className="relative w-full max-w-[560px] bg-[#13131d] border border-white/[0.1] rounded-2xl shadow-2xl shadow-black/50 overflow-hidden animate-in fade-in zoom-in-95 duration-200"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Search Input */}
        <div className="flex items-center gap-3 px-5 py-4 border-b border-white/[0.08]">
          <Search size={18} className="text-gray-500 shrink-0" />
          <input
            ref={inputRef}
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Rechercher une page, un outil..."
            className="flex-1 bg-transparent text-white text-[15px] placeholder-gray-600 outline-none"
          />
          <kbd className="hidden sm:flex items-center gap-1 px-2 py-0.5 text-[10px] text-gray-600 bg-white/[0.04] border border-white/[0.08] rounded-md font-mono">
            ESC
          </kbd>
        </div>

        {/* Results */}
        <div className="max-h-[340px] overflow-y-auto py-2 custom-scrollbar">
          {Object.keys(grouped).length === 0 ? (
            <div className="px-5 py-8 text-center text-gray-600 text-sm">Aucun r{'\u00e9'}sultat pour {'\u201C'}{query}{'\u201D'}</div>
          ) : (
            Object.entries(grouped).map(([category, cmds]) => (
              <div key={category}>
                <div className="px-5 py-2 text-[10px] font-bold text-gray-600 uppercase tracking-wider">{category}</div>
                {cmds.map((cmd) => (
                  <button
                    key={cmd.id}
                    onClick={() => { onNavigate(cmd.id); onClose(); }}
                    className="w-full flex items-center gap-3 px-5 py-2.5 text-left hover:bg-white/[0.04] transition-colors group"
                  >
                    <span className="text-base">{cmd.icon}</span>
                    <span className="text-[14px] text-gray-300 group-hover:text-white transition-colors">{cmd.label}</span>
                  </button>
                ))}
              </div>
            ))
          )}
        </div>

        {/* Footer */}
        <div className="px-5 py-3 border-t border-white/[0.06] flex items-center justify-between text-[11px] text-gray-600">
          <div className="flex items-center gap-3">
            <span className="flex items-center gap-1"><kbd className="px-1.5 py-0.5 bg-white/[0.04] border border-white/[0.08] rounded text-[10px] font-mono">{'\u2191\u2193'}</kbd> naviguer</span>
            <span className="flex items-center gap-1"><kbd className="px-1.5 py-0.5 bg-white/[0.04] border border-white/[0.08] rounded text-[10px] font-mono">{'\u21B5'}</kbd> ouvrir</span>
          </div>
          <span>CitedBy.ai</span>
        </div>
      </div>
    </div>
  );
};

const AppContent = (): JSX.Element => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [isCommandPaletteOpen, setIsCommandPaletteOpen] = useState(false);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        setIsCommandPaletteOpen(prev => !prev);
      }
      if (e.key === 'Escape') {
        setIsCommandPaletteOpen(false);
      }
    };
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, []);

  const navigateTo = (view: string) => {
    navigate('/' + view);
  };

  return (
    <Suspense fallback={<LoadingScreen />}>
      {user && <CommandPalette isOpen={isCommandPaletteOpen} onClose={() => setIsCommandPaletteOpen(false)} onNavigate={(view) => navigateTo(view)} />}
      <Routes>
        <Route path="/auth" element={<AuthPage />} />
        <Route path="/onboarding/sector" element={<SectorSelectPage />} />
        <Route element={<ProtectedShell />}>
          <Route index element={<Navigate replace to="/radar" />} />
          <Route path="/radar" element={<RadarPage />} />
          <Route path="/prospect/:id" element={<ProspectDetailPage />} />
          <Route path="/pipeline" element={<PipelinePage />} />
          <Route path="/sources" element={<SourcesPage />} />
          <Route path="/statistiques" element={<StatsPage />} />
          <Route path="/reglages" element={<SettingsPage />} />
        </Route>
        <Route path="*" element={<Navigate replace to="/radar" />} />
      </Routes>
    </Suspense>
  );
};

const App = (): JSX.Element => (
  <AuthProvider>
    <AppContent />
  </AuthProvider>
);

export default App;
"}

{"content":"import { GoogleGenAI } from "@google/genai";
import {
  MonitoringResult,
  CitationEntry,
  EngineResult,
  CompetitorData,
  TimeSeriesPoint,
  AIEngine,
  Sentiment,
  SentimentBreakdown,
} from "../types/ai-monitoring";

const getApiKey = () => {
  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
    return process.env.API_KEY;
  }
  return null;
};

// ── Deterministic helpers ──
const seededRandom = (seed: number, offset: number): number => {
  const raw = ((seed * 37 + offset * 19 + 11) * 17) % 1000;
  return raw / 1000;
};

const seededInt = (seed: number, offset: number, min: number, max: number): number => {
  return min + Math.round(seededRandom(seed, offset) * (max - min));
};

const seededFloat = (seed: number, offset: number, min: number, max: number): number => {
  return Math.round((min + seededRandom(seed, offset) * (max - min)) * 10) / 10;
};

// ── Fallback deterministic simulation ──
const fallbackSimulation = async (brandName: string, url: string, period: '7d' | '30d' | '90d' = '30d'): Promise<MonitoringResult> => {
  await new Promise(resolve => setTimeout(resolve, 2400));

  let hostname: string;
  try { hostname = new URL(url).hostname; } catch { hostname = url; }
  const brand = brandName || hostname;
  const seed = brand.length + hostname.length;

  const periodDays = period === '7d' ? 7 : period === '30d' ? 30 : 90;
  const multiplier = period === '7d' ? 1 : period === '30d' ? 3.5 : 10;

  // ── Total citations & KPIs ──
  const totalCitations = seededInt(seed, 1, Math.round(12 * multiplier), Math.round(45 * multiplier));
  const shareOfVoice = seededFloat(seed, 2, 8, 42);
  const trend = seededFloat(seed, 3, -15, 25);

  const overallSentiment: SentimentBreakdown = {
    positive: seededInt(seed, 4, 35, 65),
    neutral: seededInt(seed, 5, 20, 40),
    negative: 0,
  };
  overallSentiment.negative = 100 - overallSentiment.positive - overallSentiment.neutral;
  if (overallSentiment.negative < 0) {
    overallSentiment.neutral += overallSentiment.negative;
    overallSentiment.negative = 0;
  }

  // ── Engine results ──
  const engines: AIEngine[] = ['ChatGPT', 'Claude', 'Perplexity', 'Gemini'];
  const queryPool = [
    `meilleur ${brand.split('.')[0]} avis`,
    `${brand.split('.')[0]} vs concurrent`,
    `alternative a ${brand.split('.')[0]}`,
    `${brand.split('.')[0]} prix tarif`,
    `${brand.split('.')[0]} fiabilite`,
    `comparatif ${brand.split('.')[0]}`,
    `${brand.split('.')[0]} guide complet`,
    `recommandation ${brand.split('.')[0]}`,
    `${brand.split('.')[0]} pour entreprise`,
    `top solutions ${brand.split('.')[0]}`,
    `${brand.split('.')[0]} expertise`,
    `${brand.split('.')[0]} retour experience`,
  ];

  const engineResults: EngineResult[] = engines.map((engine, i) => {
    const engineCitations = seededInt(seed, 10 + i, Math.round(3 * multiplier), Math.round(15 * multiplier));
    const engineSov = seededFloat(seed, 20 + i, 5, 45);
    const engineSentiment: SentimentBreakdown = {
      positive: seededInt(seed, 30 + i, 30, 70),
      neutral: seededInt(seed, 40 + i, 15, 40),
      negative: 0,
    };
    engineSentiment.negative = Math.max(0, 100 - engineSentiment.positive - engineSentiment.neutral);
    if (engineSentiment.negative < 0) {
      engineSentiment.neutral += engineSentiment.negative;
      engineSentiment.negative = 0;
    }

    const topQueries = queryPool
      .sort(() => seededRandom(seed, 50 + i * 10) - 0.5)
      .slice(0, seededInt(seed, 60 + i, 3, 5));

    return {
      engine,
      totalCitations: engineCitations,
      shareOfVoice: engineSov,
      avgPosition: seededFloat(seed, 70 + i, 1, 5),
      sentiment: engineSentiment,
      trend: seededFloat(seed, 80 + i, -20, 30),
      topQueries,
    };
  });

  // ── Citations table ──
  const sentiments: Sentiment[] = ['positive', 'neutral', 'negative'];
  const citationCount = Math.min(totalCitations, 20);
  const citations: CitationEntry[] = Array.from({ length: citationCount }, (_, i) => {
    const engineIndex = i % 4;
    const sentimentIndex = seededInt(seed, 100 + i, 0, 2);
    const daysAgo = seededInt(seed, 120 + i, 0, periodDays - 1);
    const date = new Date();
    date.setDate(date.getDate() - daysAgo);

    return {
      id: `cit-${seed}-${i}`,
      engine: engines[engineIndex],
      query: queryPool[i % queryPool.length],
      position: seededInt(seed, 140 + i, 1, 8),
      date: date.toISOString().split('T')[0],
      sentiment: sentiments[sentimentIndex],
      snippet: generateSnippet(brand, engines[engineIndex], sentiments[sentimentIndex], seed + i),
      confidence: seededInt(seed, 160 + i, 60, 98),
    };
  }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  // ── Competitors ──
  const competitorNames = [
    'CompetitorAlpha', 'RivalTech', 'MarketLeader', 'IndustryStar', 'NextGenCorp'
  ];
  const competitors: CompetitorData[] = competitorNames.slice(0, 4).map((name, i) => ({
    name,
    totalCitations: seededInt(seed, 200 + i, Math.round(8 * multiplier), Math.round(50 * multiplier)),
    shareOfVoice: seededFloat(seed, 210 + i, 5, 35),
    avgSentiment: seededInt(seed, 220 + i, 40, 85),
    trend: seededFloat(seed, 230 + i, -20, 30),
    dominantEngine: engines[seededInt(seed, 240 + i, 0, 3)],
  }));

  // ── Time series ──
  const timeSeries: TimeSeriesPoint[] = Array.from({ length: periodDays }, (_, i) => {
    const date = new Date();
    date.setDate(date.getDate() - (periodDays - 1 - i));
    const daySeed = seed + i * 7;
    const chatgpt = seededInt(daySeed, 300, 0, 5);
    const claude = seededInt(daySeed, 310, 0, 4);
    const perplexity = seededInt(daySeed, 320, 0, 4);
    const gemini = seededInt(daySeed, 330, 0, 3);
    return {
      date: date.toISOString().split('T')[0],
      citations: chatgpt + claude + perplexity + gemini,
      chatgpt,
      claude,
      perplexity,
      gemini,
    };
  });

  // ── Summary & recommendations ──
  const summary = totalCitations > 80
    ? `${brand} beneficie d'une excellente visibilite sur les moteurs IA avec ${totalCitations} citations detectees sur ${periodDays} jours. Le sentiment est majoritairement positif (${overallSentiment.positive}%). La part de voix de ${shareOfVoice}% positionne la marque parmi les leaders cites.`
    : totalCitations > 30
      ? `${brand} a une visibilite moderee sur les IA generatives avec ${totalCitations} citations sur ${periodDays} jours. Le Share of Voice de ${shareOfVoice}% offre une marge de progression. Concentrez vos efforts sur les moteurs ou la marque est sous-representee.`
      : `${brand} a une faible presence dans les reponses IA (${totalCitations} citations sur ${periodDays} jours). La part de voix de ${shareOfVoice}% indique un besoin urgent d'optimisation AEO pour ameliorer la citabilite de la marque.`;

  const recommendations = [
    'Enrichir le contenu du site avec des donnees factuelles et structurees (Schema.org) pour ameliorer la citabilite.',
    'Creer des pages "hub" thematiques qui repondent directement aux questions frequentes detectees.',
    'Renforcer les signaux E-E-A-T (bios auteur, certifications, avis clients) pour gagner en autorite.',
    'Publier du contenu regulier sur les sujets ou la marque est citee pour maintenir la visibilite.',
    'Optimiser le fichier llms.txt pour guider les IA sur les informations cles de la marque.',
  ];

  return {
    brandName: brand,
    url,
    scanDate: new Date().toISOString(),
    period,
    totalCitations,
    shareOfVoice,
    overallSentiment,
    trend,
    engineResults,
    citations,
    competitors,
    timeSeries,
    summary,
    recommendations,
  };
};

function generateSnippet(brand: string, engine: AIEngine, sentiment: Sentiment, seed: number): string {
  const positiveSnippets = [
    `${brand} est frequemment recommande pour sa fiabilite et son expertise dans le domaine.`,
    `Selon les retours, ${brand} offre un excellent rapport qualite-prix et un service client reactif.`,
    `${brand} se distingue par son approche innovante et ses resultats prouves aupres de ses clients.`,
    `Les utilisateurs saluent la qualite de service de ${brand} et son expertise reconnue.`,
  ];
  const neutralSnippets = [
    `${brand} fait partie des acteurs du marche avec une offre competitive.`,
    `${brand} propose des services comparables aux standards de l'industrie.`,
    `Parmi les options disponibles, ${brand} est mentionne comme une alternative a considerer.`,
    `${brand} est present sur ce segment avec une offre qui repond aux besoins standards.`,
  ];
  const negativeSnippets = [
    `Certains utilisateurs rapportent des delais chez ${brand}, bien que la qualite soit reconnue.`,
    `${brand} pourrait ameliorer certains aspects de son service pour rester competitif.`,
    `Des alternatives a ${brand} existent pour ceux qui cherchent un meilleur rapport qualite-prix.`,
  ];

  const pool = sentiment === 'positive' ? positiveSnippets : sentiment === 'neutral' ? neutralSnippets : negativeSnippets;
  const idx = seed % pool.length;
  return pool[idx];
}

// ── Main export ──
export const runMonitoringScan = async (
  brandName: string,
  url: string,
  period: '7d' | '30d' | '90d' = '30d'
): Promise<MonitoringResult> => {
  const apiKey = getApiKey();
  if (!apiKey) {
    console.warn("API_KEY not found, using simulation.");
    return fallbackSimulation(brandName, url, period);
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    const prompt = `Tu es un expert en monitoring de visibilite de marque sur les moteurs de reponse IA (ChatGPT, Claude, Perplexity, Gemini).

Analyse la marque "${brandName}" (${url}) et genere un rapport de monitoring IA complet pour les ${period === '7d' ? '7 derniers jours' : period === '30d' ? '30 derniers jours' : '90 derniers jours'}.

Genere un JSON avec:
- totalCitations: nombre total de citations detectees
- shareOfVoice: pourcentage de part de voix (0-100)
- overallSentiment: { positive: number, neutral: number, negative: number } (somme = 100)
- trend: evolution en % vs periode precedente
- engineResults: tableau de 4 objets (ChatGPT, Claude, Perplexity, Gemini) avec totalCitations, shareOfVoice, avgPosition, sentiment, trend, topQueries
- citations: tableau de 15-20 citations recentes avec engine, query, position, date, sentiment, snippet, confidence
- competitors: tableau de 4 concurrents avec name, totalCitations, shareOfVoice, avgSentiment, trend, dominantEngine
- timeSeries: tableau de points jour par jour avec date, citations, chatgpt, claude, perplexity, gemini
- summary: resume en francais de la visibilite IA
- recommendations: 5 recommandations actionables en francais

Reponds UNIQUEMENT avec le JSON valide.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        temperature: 0.4,
      }
    });

    let output = response.text;
    if (!output) throw new Error("Empty response");
    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

    const parsed = JSON.parse(output);
    return {
      brandName,
      url,
      scanDate: new Date().toISOString(),
      period,
      ...parsed,
    };
  } catch (error) {
    console.error("AI Monitoring scan failed:", error);
    return fallbackSimulation(brandName, url, period);
  }
};
"}

{"content":"
export interface User {
  id: string;
  email: string;
  name: string;
  credits: number;
  plan: 'free' | 'pro' | 'enterprise';
  workspaceId?: string;
  role?: 'owner' | 'admin' | 'analyst' | 'viewer';
}

export interface Project {
  id: string;
  name: string;
  domain: string;
  logo?: string;
  status: 'active' | 'paused';
  lastRun?: string; // ISO Date
  visibilityScore: number;
  trend: number; // Percentage variation
  nextRun?: string;
}

export interface Recommendation {
  id: string;
  priority: 'critical' | 'high' | 'medium' | 'low';
  title: string;
  description: string;
  action: string;
  effort: 'low' | 'medium' | 'high';
  impact: 'low' | 'medium' | 'high';
  category: string;
}

export interface CategoryScore {
  name: string;
  score: number;
  weight: number;
  items: Array<{
    status: 'success' | 'warning' | 'error';
    message: string;
    recommendation?: string;
  }>;
}

export interface RobotsTxtData {
  content: string;
  isUnlocked: boolean;
  platform: string;
  generatedAt: string;
}

export interface GeneratedSolution {
  title: string;
  explanation: string;
  content: string; // Code or Text
  type: 'code' | 'text';
  language?: 'html' | 'json' | 'text';
  implementationSteps: string[]; 
}

export interface AnalysisResult {
  url: string;
  timestamp: string;
  globalScore: number;
  categories: Record<string, CategoryScore>; 
  recommendations: Recommendation[];
  aiCitation: {
    before: string;
    after: string;
    probability: number; 
  };
  robotsTxtData?: RobotsTxtData;
  generatedSolutions?: Record<string, GeneratedSolution & { timestamp: string }>;
}

export interface HistoryItem {
  id: string;
  url: string;
  score: number;
  date: string;
}

export interface SourceOfTruthData {
  description: string;
  type: string;
  founded: string;
  location: string;
  services: Array<{ name: string; description: string; category: string }>;
  faqs: Array<{ question: string; answer: string }>;
}

export interface SMCContent {
  id: string;
  type: 'fiche' | 'faq' | 'brief' | 'article';
  title: string;
  content: string;
  timestamp: string;
  meta?: any; // Pour stocker des infos sup comme le brief parent
}

// === MODULE #3 : CONTENT WRITER ===
export type ContentVertical = 'ecommerce' | 'saas' | 'immobilier' | 'restauration' | 'sante' | 'finance' | 'juridique' | 'education' | 'general';
export type ContentType = 'product_description' | 'landing_page' | 'sales_email' | 'meta_tags' | 'social_post' | 'press_release' | 'case_study' | 'newsletter';

export interface ContentWriterInput {
  vertical: ContentVertical;
  contentType: ContentType;
  brandName: string;
  brandUrl?: string;
  productOrService: string;
  targetAudience: string;
  tone: 'professionnel' | 'decontracte' | 'autoritaire' | 'empathique' | 'technique';
  language: 'fr' | 'en' | 'es';
  additionalContext?: string;
}

export interface GeneratedContent {
  title: string;
  content: string;
  metaDescription?: string;
  aeoScore: number;
  aeoTips: string[];
  schemaMarkup?: string;
  alternativeVersions?: string[];
}

// === MODULE #4 : REPUTATION ===
export interface ReputationScanInput {
  brandName: string;
  brandUrl?: string;
  competitors?: string[];
  industry: string;
  keywords?: string[];
}

export interface AIMention {
  id: string;
  aiEngine: 'ChatGPT' | 'Perplexity' | 'Claude' | 'Gemini' | 'Copilot';
  prompt: string;
  mentionType: 'direct' | 'indirect' | 'comparison' | 'recommendation' | 'negative' | 'absent';
  sentiment: 'positive' | 'neutral' | 'negative';
  sentimentScore: number;
  excerpt: string;
  context: string;
  date: string;
  competitorsMentioned?: string[];
}

export interface ReputationReport {
  brandName: string;
  overallSentiment: number;
  visibilityScore: number;
  totalMentions: number;
  sentimentBreakdown: { positive: number; neutral: number; negative: number };
  topThemes: Array<{ theme: string; count: number; sentiment: 'positive' | 'neutral' | 'negative' }>;
  competitorComparison?: Array<{ name: string; mentions: number; sentiment: number }>;
  alerts: Array<{ severity: 'critical' | 'warning' | 'info'; message: string; action: string }>;
  recommendations: string[];
  mentions: AIMention[];
  generatedAt: string;
}"}

{"content":"import React, { useState, useMemo } from 'react';
import {
  Bell, AlertTriangle, CheckCircle2, XCircle, Shield, Settings, ArrowLeft,
  Search, Filter, Info, ChevronDown, ChevronUp, ExternalLink, Clock,
  TrendingDown, Bot, FileCode, Code, Eye, BarChart3, ToggleLeft, ToggleRight
} from 'lucide-react';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface AlertsAEOProps {
  onBack: () => void;
  user: { name: string; plan: string; credits: number } | null;
  onNavigate?: (view: string) => void;
}

type AlertSeverity = 'critical' | 'warning' | 'info' | 'resolved';

interface AEOAlert {
  id: string;
  severity: AlertSeverity;
  title: string;
  description: string;
  details: string;
  affectedUrl: string;
  timestamp: string;
  relativeTime: string;
  category: string;
}

interface AlertSetting {
  id: string;
  label: string;
  description: string;
  enabled: boolean;
}

// ---------------------------------------------------------------------------
// Severity configuration
// ---------------------------------------------------------------------------

const SEVERITY_CONFIG: Record<AlertSeverity, {
  icon: React.ElementType;
  color: string;
  bg: string;
  border: string;
  badge: string;
  label: string;
}> = {
  critical: {
    icon: XCircle,
    color: 'text-red-400',
    bg: 'bg-red-500/10',
    border: 'border-l-red-500',
    badge: 'bg-red-500/15 text-red-400 border-red-500/20',
    label: 'Critique',
  },
  warning: {
    icon: AlertTriangle,
    color: 'text-yellow-400',
    bg: 'bg-yellow-500/10',
    border: 'border-l-yellow-500',
    badge: 'bg-yellow-500/15 text-yellow-400 border-yellow-500/20',
    label: 'Warning',
  },
  info: {
    icon: Info,
    color: 'text-blue-400',
    bg: 'bg-blue-500/10',
    border: 'border-l-blue-500',
    badge: 'bg-blue-500/15 text-blue-400 border-blue-500/20',
    label: 'Info',
  },
  resolved: {
    icon: CheckCircle2,
    color: 'text-green-400',
    bg: 'bg-green-500/10',
    border: 'border-l-green-500',
    badge: 'bg-green-500/15 text-green-400 border-green-500/20',
    label: 'Résolu',
  },
};

// ---------------------------------------------------------------------------
// Demo data
// ---------------------------------------------------------------------------

const DEMO_ALERTS: AEOAlert[] = [
  {
    id: 'alert-001',
    severity: 'critical',
    title: 'Score AEO en chute libre (-23 pts)',
    description: 'Le score AEO de votre page principale est passé de 82 à 59 en 24h. Cela pourrait affecter significativement votre visibilité dans les réponses IA.',
    details: 'Analyse détaillée : La baisse est principalement due à une modification récente du contenu qui a supprimé plusieurs balises Schema.org structurées. Les sections FAQ et HowTo ont été retirées lors de la dernière mise à jour. Recommandation : restaurer les données structurées et ajouter des balises Question/Answer pour améliorer le score.',
    affectedUrl: 'monsite.com/guide-seo-2025',
    timestamp: '2025-06-15T14:30:00Z',
    relativeTime: 'Il y a 2h',
    category: 'score',
  },
  {
    id: 'alert-002',
    severity: 'critical',
    title: 'Citation IA perdue sur ChatGPT',
    description: 'Votre site n\'apparaît plus dans les réponses de ChatGPT pour la requête "meilleur outil SEO 2025". Perte de visibilité critique.',
    details: 'Votre contenu était cité dans 78% des réponses ChatGPT pour cette requête la semaine dernière. Depuis hier, le taux est tombé à 0%. Un concurrent (seotool.io) semble avoir pris votre place avec un contenu mis à jour. Action recommandée : mettre à jour votre contenu avec des données 2025 récentes et renforcer l\'autorité de la page.',
    affectedUrl: 'monsite.com/comparatif-outils-seo',
    timestamp: '2025-06-15T12:00:00Z',
    relativeTime: 'Il y a 4h',
    category: 'citation',
  },
  {
    id: 'alert-003',
    severity: 'warning',
    title: 'Nouveau bot IA détecté : Grok-Crawler',
    description: 'Un nouveau crawler IA (Grok-Crawler, xAI) a été détecté sur votre site. 47 pages crawlées en 3h. Aucune règle robots.txt configurée.',
    details: 'Le bot Grok-Crawler (User-Agent: Grok-Crawler/1.0) a commencé à indexer votre site ce matin. Il crawle principalement vos pages de blog et documentation. Votre robots.txt actuel ne contient aucune directive pour ce bot. Nous recommandons de définir des règles d\'accès appropriées.',
    affectedUrl: 'monsite.com (global)',
    timestamp: '2025-06-15T11:15:00Z',
    relativeTime: 'Il y a 5h',
    category: 'bot',
  },
  {
    id: 'alert-004',
    severity: 'warning',
    title: 'Changement robots.txt détecté',
    description: 'Votre fichier robots.txt a été modifié. La directive "Allow: /blog/" pour GPTBot a été supprimée, ce qui pourrait bloquer l\'indexation IA.',
    details: 'Modification détectée à 09:42 ce matin. Les changements incluent : suppression de "User-agent: GPTBot / Allow: /blog/" et ajout de "User-agent: * / Disallow: /api/". Cela impacte potentiellement l\'accès de GPTBot et ClaudeBot à votre contenu blog. Vérifiez si ce changement est intentionnel.',
    affectedUrl: 'monsite.com/robots.txt',
    timestamp: '2025-06-15T09:42:00Z',
    relativeTime: 'Il y a 7h',
    category: 'robots',
  },
  {
    id: 'alert-005',
    severity: 'warning',
    title: 'Taux de citation Perplexity en baisse',
    description: 'Le taux de citation de votre domaine sur Perplexity AI a baissé de 12% cette semaine par rapport à la semaine précédente.',
    details: 'Semaine précédente : 34% de taux de citation moyen. Cette semaine : 22%. Les requêtes les plus impactées concernent "formation marketing digital" et "stratégie content marketing". Un concurrent a publié un guide complet qui semble être préféré par Perplexity.',
    affectedUrl: 'monsite.com/formation-marketing',
    timestamp: '2025-06-15T08:00:00Z',
    relativeTime: 'Il y a 8h',
    category: 'citation',
  },
  {
    id: 'alert-006',
    severity: 'info',
    title: 'Nouvelle source de trafic IA identifiée',
    description: 'Copilot (Microsoft) génère désormais du trafic vers votre site. 23 visites détectées cette semaine via des réponses IA.',
    details: 'Microsoft Copilot cite désormais votre contenu pour des requêtes liées à "optimisation AEO" et "référencement IA". Le trafic provient principalement de Copilot intégré à Bing et Edge. C\'est une opportunité de renforcer votre positionnement sur cette plateforme.',
    affectedUrl: 'monsite.com/blog/aeo-guide',
    timestamp: '2025-06-14T18:00:00Z',
    relativeTime: 'Il y a 22h',
    category: 'citation',
  },
  {
    id: 'alert-007',
    severity: 'info',
    title: 'Erreur Schema.org détectée sur 3 pages',
    description: 'Le validateur a détecté des erreurs dans les balises Schema.org de 3 pages. Les champs "author" et "dateModified" sont manquants.',
    details: 'Pages concernées :\n- /blog/guide-aeo (manque "author", "dateModified")\n- /blog/seo-tips-2025 (manque "dateModified")\n- /services/audit (manque "author", "publisher")\nCes champs sont importants pour que les IA puissent correctement attribuer et dater votre contenu.',
    affectedUrl: 'monsite.com (3 pages)',
    timestamp: '2025-06-14T14:30:00Z',
    relativeTime: 'Hier',
    category: 'schema',
  },
  {
    id: 'alert-008',
    severity: 'info',
    title: 'Pic de crawl IA détecté',
    description: 'Le volume de crawl IA a augmenté de 340% sur les dernières 6h. Principalement GPTBot et ClaudeBot.',
    details: 'Volume normal : ~50 requêtes/heure. Volume actuel : ~220 requêtes/heure. Les bots se concentrent sur vos pages /blog/ et /docs/. Cela peut indiquer une re-indexation en cours ou un intérêt accru pour votre contenu récemment mis à jour. Aucune action requise si votre serveur supporte la charge.',
    affectedUrl: 'monsite.com (global)',
    timestamp: '2025-06-14T10:00:00Z',
    relativeTime: 'Hier',
    category: 'bot',
  },
  {
    id: 'alert-009',
    severity: 'resolved',
    title: 'Score AEO restauré sur /pricing',
    description: 'Le score AEO de la page /pricing est remonté à 78 (était à 45). Les corrections Schema.org ont été prises en compte.',
    details: 'Suite à l\'alerte du 12 juin, les corrections apportées (ajout de données structurées Product, FAQ et Organization) ont été indexées par les crawlers IA. Le score est passé de 45 à 78 en 48h. Continuez à monitorer pour confirmer la stabilité.',
    affectedUrl: 'monsite.com/pricing',
    timestamp: '2025-06-14T08:00:00Z',
    relativeTime: 'Hier',
    category: 'score',
  },
  {
    id: 'alert-010',
    severity: 'resolved',
    title: 'Directive robots.txt corrigée pour ClaudeBot',
    description: 'La directive Allow pour ClaudeBot a été correctement ajoutée au robots.txt. Le bot peut à nouveau accéder au contenu.',
    details: 'Suite à l\'alerte du 10 juin signalant un blocage involontaire de ClaudeBot, la directive a été mise à jour. ClaudeBot a repris le crawl avec succès : 34 pages indexées depuis la correction. Le taux de citation sur Claude devrait se rétablir sous 48-72h.',
    affectedUrl: 'monsite.com/robots.txt',
    timestamp: '2025-06-13T16:00:00Z',
    relativeTime: 'Il y a 2 jours',
    category: 'robots',
  },
];

const DEFAULT_SETTINGS: AlertSetting[] = [
  { id: 'score-drop', label: 'Score AEO en baisse', description: 'Alerte si le score AEO baisse de plus de 10 points', enabled: true },
  { id: 'new-bot', label: 'Nouveau bot détecté', description: 'Notification lors de la détection d\'un nouveau crawler IA', enabled: true },
  { id: 'citation-lost', label: 'Citation IA perdue', description: 'Alerte si une citation IA disparaît', enabled: true },
  { id: 'robots-change', label: 'Changement robots.txt', description: 'Alerte en cas de modification du robots.txt', enabled: true },
  { id: 'schema-error', label: 'Erreur Schema.org', description: 'Notification pour les erreurs de données structurées', enabled: false },
];

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

const AlertsAEO: React.FC<AlertsAEOProps> = ({ onBack, user, onNavigate }) => {
  const [activeFilter, setActiveFilter] = useState<'all' | AlertSeverity>('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [expandedAlertId, setExpandedAlertId] = useState<string | null>(null);
  const [resolvedAlerts, setResolvedAlerts] = useState<Set<string>>(new Set());
  const [alertSettings, setAlertSettings] = useState<AlertSetting[]>(DEFAULT_SETTINGS);

  // Derive alert list with resolved overrides
  const alerts = useMemo(() => {
    return DEMO_ALERTS.map((alert) => {
      if (resolvedAlerts.has(alert.id) && alert.severity !== 'resolved') {
        return { ...alert, severity: 'resolved' as AlertSeverity };
      }
      return alert;
    });
  }, [resolvedAlerts]);

  // Filter + search
  const filteredAlerts = useMemo(() => {
    let list = alerts;

    if (activeFilter !== 'all') {
      list = list.filter((a) => a.severity === activeFilter);
    }

    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      list = list.filter(
        (a) =>
          a.title.toLowerCase().includes(q) ||
          a.description.toLowerCase().includes(q) ||
          a.affectedUrl.toLowerCase().includes(q)
      );
    }

    return list;
  }, [alerts, activeFilter, searchQuery]);

  // KPI counts
  const kpis = useMemo(() => {
    const critical = alerts.filter((a) => a.severity === 'critical').length;
    const warning = alerts.filter((a) => a.severity === 'warning').length;
    const info = alerts.filter((a) => a.severity === 'info').length;
    const resolved = alerts.filter((a) => a.severity === 'resolved').length;
    return { critical, warning, info, resolved };
  }, [alerts]);

  const totalActive = kpis.critical + kpis.warning + kpis.info;

  // Handlers
  const toggleExpand = (id: string) => {
    setExpandedAlertId((prev) => (prev === id ? null : id));
  };

  const markResolved = (id: string) => {
    setResolvedAlerts((prev) => new Set(prev).add(id));
    setExpandedAlertId(null);
  };

  const toggleSetting = (settingId: string) => {
    setAlertSettings((prev) =>
      prev.map((s) => (s.id === settingId ? { ...s, enabled: !s.enabled } : s))
    );
  };

  // Category icon helper
  const getCategoryIcon = (category: string) => {
    switch (category) {
      case 'score': return TrendingDown;
      case 'citation': return Eye;
      case 'bot': return Bot;
      case 'robots': return FileCode;
      case 'schema': return Code;
      default: return Bell;
    }
  };

  // Filter buttons config
  const filterButtons: { key: 'all' | AlertSeverity; label: string; color: string; count?: number }[] = [
    { key: 'all', label: 'Toutes', color: 'text-white bg-white/10', count: alerts.length },
    { key: 'critical', label: 'Critiques', color: 'text-red-400 bg-red-500/10', count: kpis.critical },
    { key: 'warning', label: 'Warnings', color: 'text-yellow-400 bg-yellow-500/10', count: kpis.warning },
    { key: 'info', label: 'Info', color: 'text-blue-400 bg-blue-500/10', count: kpis.info },
    { key: 'resolved', label: 'Résolues', color: 'text-green-400 bg-green-500/10', count: kpis.resolved },
  ];

  // -------------------------------------------------------------------------
  // Render
  // -------------------------------------------------------------------------

  return (
    <div className="w-full px-4 sm:px-6 py-6 sm:py-8 animate-in fade-in duration-500">

      {/* ---- Header ---- */}
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 mb-8">
        <div className="flex items-center gap-4">
          <button
            onClick={onBack}
            className="p-2 rounded-xl bg-[#111111] border border-white/[0.08] hover:bg-white/10 transition-colors"
            aria-label="Retour"
          >
            <ArrowLeft size={20} className="text-gray-400" />
          </button>
          <div>
            <div className="flex items-center gap-3">
              <h1 className="text-2xl sm:text-3xl font-bold font-sans text-white">
                Alertes AEO
              </h1>
              <span className="flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-semibold bg-purple-500/10 text-purple-400 border border-primary/20">
                <Bell size={13} />
                {totalActive} active{totalActive > 1 ? 's' : ''}
              </span>
            </div>
            <p className="text-sm text-gray-500 mt-1">
              Surveillez et gérez les alertes de votre visibilité IA en temps réel
            </p>
          </div>
        </div>

        {user && (
          <div className="flex items-center gap-2 text-xs text-gray-500">
            <Shield size={14} className="text-purple-400" />
            <span>Plan {user.plan}</span>
            <span className="text-white/20">|</span>
            <span>{user.credits} crédits</span>
          </div>
        )}
      </div>

      {/* ---- KPI Row ---- */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        {/* Critical */}
        <div className="bg-[#111111] border border-white/[0.08] rounded-2xl p-5 transition-all hover:border-red-500/20">
          <div className="flex items-center justify-between mb-3">
            <div className="p-2 rounded-xl bg-red-500/10">
              <XCircle size={20} className="text-red-400" />
            </div>
            <span className="text-3xl font-bold text-red-400">{kpis.critical}</span>
          </div>
          <p className="text-sm font-semibold text-gray-300">Alertes Critiques</p>
          <p className="text-xs text-gray-500 mt-0.5">Action immédiate requise</p>
        </div>

        {/* Warning */}
        <div className="bg-[#111111] border border-white/[0.08] rounded-2xl p-5 transition-all hover:border-yellow-500/20">
          <div className="flex items-center justify-between mb-3">
            <div className="p-2 rounded-xl bg-yellow-500/10">
              <AlertTriangle size={20} className="text-yellow-400" />
            </div>
            <span className="text-3xl font-bold text-yellow-400">{kpis.warning}</span>
          </div>
          <p className="text-sm font-semibold text-gray-300">Alertes Warning</p>
          <p className="text-xs text-gray-500 mt-0.5">A surveiller de près</p>
        </div>

        {/* Info */}
        <div className="bg-[#111111] border border-white/[0.08] rounded-2xl p-5 transition-all hover:border-blue-500/20">
          <div className="flex items-center justify-between mb-3">
            <div className="p-2 rounded-xl bg-blue-500/10">
              <Info size={20} className="text-blue-400" />
            </div>
            <span className="text-3xl font-bold text-blue-400">{kpis.info}</span>
          </div>
          <p className="text-sm font-semibold text-gray-300">Alertes Info</p>
          <p className="text-xs text-gray-500 mt-0.5">Pour information</p>
        </div>

        {/* Resolved */}
        <div className="bg-[#111111] border border-white/[0.08] rounded-2xl p-5 transition-all hover:border-green-500/20">
          <div className="flex items-center justify-between mb-3">
            <div className="p-2 rounded-xl bg-green-500/10">
              <CheckCircle2 size={20} className="text-green-400" />
            </div>
            <span className="text-3xl font-bold text-green-400">{kpis.resolved}</span>
          </div>
          <p className="text-sm font-semibold text-gray-300">Résolues ce mois</p>
          <p className="text-xs text-gray-500 mt-0.5">Problèmes corrigés</p>
        </div>
      </div>

      {/* ---- Main layout: Alert list + Sidebar ---- */}
      <div className="flex flex-col lg:flex-row gap-6">

        {/* ---- Left: Alert list (2/3) ---- */}
        <div className="w-full lg:w-2/3 space-y-6">

          {/* Filter bar */}
          <div className="bg-[#111111] border border-white/[0.08] rounded-2xl p-4">
            <div className="flex flex-col sm:flex-row items-start sm:items-center gap-3">
              {/* Filter pills */}
              <div className="flex items-center gap-2 flex-wrap">
                <Filter size={16} className="text-gray-500 mr-1 hidden sm:block" />
                {filterButtons.map((btn) => (
                  <button
                    key={btn.key}
                    onClick={() => setActiveFilter(btn.key)}
                    className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-all ${
                      activeFilter === btn.key
                        ? `${btn.color} border border-current/20`
                        : 'text-gray-500 hover:text-gray-300 bg-transparent'
                    }`}
                  >
                    {btn.label}
                    {btn.count !== undefined && (
                      <span className="ml-1.5 opacity-70">({btn.count})</span>
                    )}
                  </button>
                ))}
              </div>

              {/* Search */}
              <div className="relative w-full sm:w-auto sm:ml-auto">
                <input
                  type="text"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder="Rechercher une alerte..."
                  className="bg-[#1a1d21] border border-white/[0.08] rounded-xl py-2 pl-9 pr-4 text-sm text-gray-300 focus:outline-none focus:border-purple-500/50 w-full sm:w-64 placeholder:text-gray-600"
                />
                <Search size={15} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
              </div>
            </div>
          </div>

          {/* Alert cards */}
          <div className="space-y-3">
            {filteredAlerts.length === 0 ? (
              <div className="bg-[#111111] border border-white/[0.08] rounded-2xl p-12 text-center">
                <Bell size={40} className="text-gray-600 mx-auto mb-4" />
                <p className="text-gray-400 font-semibold">Aucune alerte trouvée</p>
                <p className="text-sm text-gray-600 mt-1">
                  {searchQuery ? 'Essayez un autre terme de recherche' : 'Aucune alerte dans cette catégorie'}
                </p>
              </div>
            ) : (
              filteredAlerts.map((alert, index) => {
                const config = SEVERITY_CONFIG[alert.severity];
                const SeverityIcon = config.icon;
                const CategoryIcon = getCategoryIcon(alert.category);
                const isExpanded = expandedAlertId === alert.id;
                const isResolvable = alert.severity !== 'resolved';

                return (
                  <div
                    key={alert.id}
                    className={`bg-[#111111] border border-white/[0.08] rounded-2xl overflow-hidden transition-all duration-300 hover:border-white/[0.12] ${
                      index < 3 ? 'animate-in fade-in duration-500' : ''
                    }`}
                    style={{ animationDelay: `${index * 80}ms` }}
                  >
                    {/* Card with colored left border */}
                    <div className={`border-l-4 ${config.border} p-4 sm:p-5`}>

                      {/* Top row: icon + title + timestamp */}
                      <div className="flex items-start gap-3">
                        {/* Severity + Category icons */}
                        <div className="flex flex-col items-center gap-1.5 mt-0.5">
                          <div className={`p-1.5 rounded-lg ${config.bg}`}>
                            <SeverityIcon size={16} className={config.color} />
                          </div>
                          <CategoryIcon size={12} className="text-gray-600" />
                        </div>

                        {/* Content */}
                        <div className="flex-1 min-w-0">
                          <div className="flex items-start justify-between gap-2 mb-1.5">
                            <h3 className="text-sm sm:text-base font-bold text-white leading-tight">
                              {alert.title}
                            </h3>
                            <div className="flex items-center gap-2 shrink-0">
                              <span className={`hidden sm:inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-semibold border ${config.badge}`}>
                                {config.label}
                              </span>
                              <span className="flex items-center gap-1 text-xs text-gray-500 whitespace-nowrap">
                                <Clock size={11} />
                                {alert.relativeTime}
                              </span>
                            </div>
                          </div>

                          <p className="text-sm text-gray-400 leading-relaxed mb-2">
                            {alert.description}
                          </p>

                          {/* Affected URL */}
                          <div className="flex items-center gap-1.5 mb-3">
                            <ExternalLink size={12} className="text-gray-600" />
                            <span className="text-xs text-purple-400/80 font-mono truncate">
                              {alert.affectedUrl}
                            </span>
                          </div>

                          {/* Expanded details */}
                          {isExpanded && (
                            <div className="bg-[#1a1d21] border border-white/[0.06] rounded-xl p-4 mb-3 animate-in fade-in duration-300">
                              <h4 className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-2">
                                Détails complets
                              </h4>
                              <p className="text-sm text-gray-300 leading-relaxed whitespace-pre-line">
                                {alert.details}
                              </p>
                            </div>
                          )}

                          {/* Action buttons */}
                          <div className="flex items-center gap-2 flex-wrap">
                            <button
                              onClick={() => toggleExpand(alert.id)}
                              className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold bg-white/5 hover:bg-white/10 text-gray-300 transition-colors"
                            >
                              {isExpanded ? (
                                <>
                                  <ChevronUp size={13} />
                                  Masquer détails
                                </>
                              ) : (
                                <>
                                  <ChevronDown size={13} />
                                  Voir détails
                                </>
                              )}
                            </button>

                            {isResolvable && (
                              <button
                                onClick={() => markResolved(alert.id)}
                                className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold bg-green-500/10 hover:bg-green-500/20 text-green-400 transition-colors"
                              >
                                <CheckCircle2 size={13} />
                                Marquer résolu
                              </button>
                            )}

                            {alert.severity === 'resolved' && (
                              <span className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold bg-green-500/10 text-green-400/60 cursor-default">
                                <CheckCircle2 size={13} />
                                Résolu
                              </span>
                            )}
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </div>

        {/* ---- Right: Sidebar (1/3) ---- */}
        <div className="w-full lg:w-1/3 space-y-6">

          {/* Configuration des alertes */}
          <div className="bg-[#111111] border border-white/[0.08] rounded-2xl p-5">
            <div className="flex items-center gap-2.5 mb-5">
              <div className="p-2 rounded-xl bg-purple-500/10">
                <Settings size={18} className="text-purple-400" />
              </div>
              <h2 className="text-base font-bold text-white">Configuration des alertes</h2>
            </div>

            <div className="space-y-1">
              {alertSettings.map((setting) => (
                <div
                  key={setting.id}
                  className="flex items-center justify-between gap-3 p-3 rounded-xl hover:bg-white/[0.02] transition-colors"
                >
                  <div className="min-w-0">
                    <p className="text-sm font-semibold text-gray-300">{setting.label}</p>
                    <p className="text-xs text-gray-500 mt-0.5 leading-snug">{setting.description}</p>
                  </div>
                  <button
                    onClick={() => toggleSetting(setting.id)}
                    className="shrink-0 transition-colors"
                    aria-label={`Toggle ${setting.label}`}
                  >
                    {setting.enabled ? (
                      <ToggleRight size={28} className="text-purple-400" />
                    ) : (
                      <ToggleLeft size={28} className="text-gray-600" />
                    )}
                  </button>
                </div>
              ))}
            </div>

            <div className="mt-4 pt-4 border-t border-white/[0.06]">
              <button className="w-full flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl text-sm font-semibold bg-purple-500/10 hover:bg-purple-500/20 text-purple-400 transition-colors">
                <Bell size={15} />
                Configurer les notifications
              </button>
            </div>
          </div>

          {/* Résumé hebdomadaire */}
          <div className="bg-[#111111] border border-white/[0.08] rounded-2xl p-5">
            <div className="flex items-center gap-2.5 mb-5">
              <div className="p-2 rounded-xl bg-blue-500/10">
                <BarChart3 size={18} className="text-blue-400" />
              </div>
              <h2 className="text-base font-bold text-white">Résumé hebdomadaire</h2>
            </div>

            {/* Mini chart placeholder */}
            <div className="bg-[#1a1d21] border border-white/[0.06] rounded-xl p-4 mb-4">
              <div className="flex items-end justify-between gap-1.5 h-24">
                {[
                  { day: 'Lun', critical: 1, warning: 2, info: 1 },
                  { day: 'Mar', critical: 0, warning: 3, info: 2 },
                  { day: 'Mer', critical: 2, warning: 1, info: 0 },
                  { day: 'Jeu', critical: 1, warning: 2, info: 3 },
                  { day: 'Ven', critical: 0, warning: 1, info: 1 },
                  { day: 'Sam', critical: 0, warning: 0, info: 2 },
                  { day: 'Dim', critical: 1, warning: 1, info: 0 },
                ].map((d) => {
                  const total = d.critical + d.warning + d.info;
                  const maxH = 80; // px
                  const scale = total > 0 ? total / 7 : 0;

                  return (
                    <div key={d.day} className="flex flex-col items-center gap-1 flex-1">
                      <div className="flex flex-col-reverse gap-0.5 w-full max-w-[20px]">
                        {d.critical > 0 && (
                          <div
                            className="bg-red-500/60 rounded-sm w-full"
                            style={{ height: `${(d.critical / 7) * maxH}px` }}
                          />
                        )}
                        {d.warning > 0 && (
                          <div
                            className="bg-yellow-500/60 rounded-sm w-full"
                            style={{ height: `${(d.warning / 7) * maxH}px` }}
                          />
                        )}
                        {d.info > 0 && (
                          <div
                            className="bg-blue-500/60 rounded-sm w-full"
                            style={{ height: `${(d.info / 7) * maxH}px` }}
                          />
                        )}
                        {total === 0 && (
                          <div className="bg-white/5 rounded-sm w-full" style={{ height: '4px' }} />
                        )}
                      </div>
                      <span className="text-[10px] text-gray-600">{d.day}</span>
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Weekly stats */}
            <div className="space-y-2.5">
              <div className="flex items-center justify-between text-sm">
                <span className="text-gray-400">Total cette semaine</span>
                <span className="font-bold text-white">21 alertes</span>
              </div>
              <div className="flex items-center justify-between text-sm">
                <span className="text-gray-400">Temps moyen résolution</span>
                <span className="font-bold text-white">4.2h</span>
              </div>
              <div className="flex items-center justify-between text-sm">
                <span className="text-gray-400">Taux de résolution</span>
                <span className="font-bold text-green-400">87%</span>
              </div>
            </div>

            <div className="mt-4 pt-4 border-t border-white/[0.06]">
              <div className="flex items-center gap-2 text-xs text-gray-500">
                <Clock size={12} />
                <span>Mis à jour il y a 15 min</span>
              </div>
            </div>
          </div>

          {/* Quick actions */}
          <div className="bg-[#111111] border border-white/[0.08] rounded-2xl p-5">
            <h3 className="text-sm font-bold text-white mb-3">Actions rapides</h3>
            <div className="space-y-2">
              <button
                onClick={() => onNavigate?.('bot-tracking')}
                className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm text-gray-400 hover:text-white hover:bg-white/[0.04] transition-colors text-left"
              >
                <Bot size={16} className="text-purple-400 shrink-0" />
                Voir le suivi des bots IA
              </button>
              <button
                onClick={() => onNavigate?.('robots-txt')}
                className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm text-gray-400 hover:text-white hover:bg-white/[0.04] transition-colors text-left"
              >
                <FileCode size={16} className="text-blue-400 shrink-0" />
                Configurer robots.txt
              </button>
              <button
                onClick={() => onNavigate?.('schema-org')}
                className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm text-gray-400 hover:text-white hover:bg-white/[0.04] transition-colors text-left"
              >
                <Code size={16} className="text-green-400 shrink-0" />
                Générateur Schema.org
              </button>
              <button
                onClick={() => onNavigate?.('dashboard')}
                className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm text-gray-400 hover:text-white hover:bg-white/[0.04] transition-colors text-left"
              >
                <BarChart3 size={16} className="text-yellow-400 shrink-0" />
                Retour au Dashboard
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AlertsAEO;
"}

{"content":"import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { Fuel, Check, CreditCard, Loader2, Droplet, Database, ArrowLeft, ShieldCheck, Lock, Infinity, CheckCircle2, FileText, Download, XCircle, LayoutDashboard, RefreshCcw, Wrench } from 'lucide-react';
import jsPDF from 'jspdf';
import StripeCheckout from '../components/StripeCheckout';

interface Props {
  onBack: () => void;
  onRecharge: (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => void;
  user: User | null;
  onNavigate?: (view: string) => void;
  initialPackId?: number | null;
}

const Recharge: React.FC<Props> = ({ onBack, onRecharge, user, onNavigate, initialPackId }) => {
  const [viewMode, setViewMode] = useState<'list' | 'checkout' | 'result'>('list');
  const [paymentStatus, setPaymentStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [selectedPack, setSelectedPack] = useState<typeof packs[0] | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [invoiceId, setInvoiceId] = useState<string>('');

  const packs = [
    {
      id: 1,
      name: "Le Jerrican",
      amount: 50,
      price: 15,
      icon: <Droplet size={32} />,
      popular: false,
      level: 'free' as const,
      features: ["Idéal pour un audit ponctuel", "Valable 1 an"]
    },
    {
      id: 2,
      name: "La Pompe",
      amount: 200,
      price: 49,
      icon: <Fuel size={32} />,
      popular: true,
      level: 'pro' as const,
      features: ["Pour les optimisations régulières", "Support prioritaire", "+10% Bonus offert"]
    },
    {
      id: 3,
      name: "La Citerne",
      amount: 1000,
      price: 199,
      icon: <Database size={32} />,
      popular: false,
      level: 'enterprise' as const,
      features: ["Usage intensif / Agence", "Accès API Beta", "+20% Bonus offert"]
    }
  ];

  // Effet pour sélectionner automatiquement un pack si initialPackId est fourni
  useEffect(() => {
    if (initialPackId) {
        const targetPack = packs.find(p => p.id === initialPackId);
        if (targetPack) {
            setSelectedPack(targetPack);
            setViewMode('checkout');
        }
    }
  }, [initialPackId]);

  const handleSelectPack = (pack: typeof packs[0]) => {
    setSelectedPack(pack);
    setViewMode('checkout');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleConfirmPayment = () => {
    if (!selectedPack) return;
    setIsProcessing(true);
    setPaymentStatus('idle');

    // Simulation délai paiement et résultat aléatoire (90% de succès pour l'UX)
    setTimeout(() => {
      const isSuccess = Math.random() > 0.1;

      if (isSuccess) {
        onRecharge(selectedPack.amount, selectedPack.level);
        const newInvoiceId = `INV-${new Date().getFullYear()}-${Math.floor(Math.random() * 10000).toString().padStart(4, '0')}`;
        setInvoiceId(newInvoiceId);
        setPaymentStatus('success');
      } else {
        setPaymentStatus('error');
      }

      setIsProcessing(false);
      setViewMode('result');
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }, 2000);
  };

  const generateInvoicePDF = () => {
    if (!selectedPack || !user) return;

    const doc = new jsPDF();
    const priceHT = selectedPack.price;
    const tva = priceHT * 0.20;
    const totalTTC = priceHT + tva;
    const date = new Date().toLocaleDateString('fr-FR');

    // Header
    doc.setFontSize(22);
    doc.setFont("helvetica", "bold");
    doc.text("CitedBy.ai", 20, 20);

    doc.setFontSize(10);
    doc.setFont("helvetica", "normal");
    doc.text("Facture N° " + invoiceId, 20, 30);
    doc.text("Date : " + date, 20, 35);

    // Client Info
    doc.text("Facturé à :", 140, 30);
    doc.setFont("helvetica", "bold");
    doc.text(user.name || "Client", 140, 35);
    doc.setFont("helvetica", "normal");
    doc.text(user.email || "", 140, 40);

    // Line Items Header
    doc.line(20, 55, 190, 55);
    doc.setFont("helvetica", "bold");
    doc.text("Description", 20, 62);
    doc.text("Quantité", 120, 62);
    doc.text("Montant HT", 160, 62);
    doc.line(20, 66, 190, 66);

    // Item
    doc.setFont("helvetica", "normal");
    doc.text(`Pack GTO Gas: ${selectedPack.name} (${selectedPack.amount} crédits)`, 20, 75);
    doc.text("1", 125, 75);
    doc.text(`${priceHT.toFixed(2)} €`, 160, 75);

    // Totals
    doc.line(20, 90, 190, 90);
    doc.text("Sous-total HT :", 130, 100);
    doc.text(`${priceHT.toFixed(2)} €`, 160, 100);

    doc.text("TVA (20%) :", 130, 107);
    doc.text(`${tva.toFixed(2)} €`, 160, 107);

    doc.setFont("helvetica", "bold");
    doc.setFontSize(12);
    doc.text("Total TTC :", 130, 117);
    doc.text(`${totalTTC.toFixed(2)} €`, 160, 117);

    // Footer
    doc.setFontSize(8);
    doc.setFont("helvetica", "italic");
    doc.text("Merci de votre confiance. Cette facture a été réglée par carte bancaire.", 20, 140);
    doc.text("CitedBy Inc. - 123 Avenue de l'IA, Paris, France - SIRET 123 456 789", 20, 280);

    doc.save(`Facture_${invoiceId}.pdf`);
  };

  const renderList = () => (
    <div className="animate-in fade-in slide-in-from-left duration-500">
        <div className="text-center mb-16">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-accent/20 rounded-2xl mb-6 text-accent border border-accent/20 shadow-[0_0_30px_rgba(168,85,247,0.2)]">
            <Fuel size={32} />
            </div>
            <h1 className="text-4xl font-bold text-white mb-4">GTO <span className="gradient-text">Gas Station</span></h1>
            <p className="text-gray-500 max-w-xl mx-auto text-lg">
            Le carburant essentiel pour propulser votre visibilité dans les moteurs de réponse.
            <br />
            <span className="text-sm mt-2 block text-gray-500">Solde actuel : <span className="text-white font-bold">{user?.credits || 0} Gas</span></span>
            </p>
        </div>

        <div className="grid md:grid-cols-3 gap-8 w-full">
            {packs.map((pack) => (
            <div 
                key={pack.id} 
                className={`relative ninja-card p-8 flex flex-col transition-all duration-300 hover:transform hover:-translate-y-2 ${
                pack.popular
                    ? 'gradient-border !border-purple-500/30 shadow-[0_0_40px_rgba(168,85,247,0.15)] scale-105 z-10'
                    : ''
                }`}
            >
                {pack.popular && (
                <>
                <div className="absolute -top-4 left-1/2 -translate-x-1/2 bg-gradient-to-r from-purple-500 to-violet-500 text-white font-bold text-xs px-4 py-1.5 rounded-full uppercase tracking-wider shadow-lg shadow-purple-900/40 flex items-center gap-1.5">
                    <span className="animate-pulse">⭐</span> Meilleure Offre
                </div>
                <div className="absolute -top-px -left-px -right-px -bottom-px rounded-2xl bg-gradient-to-r from-purple-500/20 to-violet-500/20 -z-10 blur-sm" />
                </>
                )}

                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center mb-6 ${pack.popular ? 'bg-accent/20 text-accent' : 'bg-white/[0.04] text-gray-500'}`}>
                {pack.icon}
                </div>

                <h3 className="text-xl font-bold text-white mb-2">{pack.name}</h3>
                <div className="flex items-baseline gap-1 mb-6">
                <span className="text-4xl font-bold gradient-text">{pack.amount}</span>
                <span className="text-sm text-gray-500 font-medium">Gas</span>
                </div>

                <ul className="space-y-3 mb-8 flex-1">
                {pack.features.map((feat, i) => (
                    <li key={i} className="flex items-start gap-3 text-sm text-gray-300">
                    <Check size={16} className={`mt-0.5 ${pack.popular ? 'text-accent' : 'text-gray-500'}`} />
                    {feat}
                    </li>
                ))}
                </ul>

                <div className="border-t border-white/[0.08] pt-6 mb-6">
                <div className="flex justify-between items-center mb-2">
                    <span className="text-gray-500">Prix HT</span>
                    <span className="text-xl font-bold text-white">{pack.price}€</span>
                </div>
                </div>

                <button
                onClick={() => handleSelectPack(pack)}
                className="w-full py-3.5 btn-gradient font-bold flex items-center justify-center gap-2 transition-all"
                >
                    <CreditCard size={18} /> Acheter
                </button>
            </div>
            ))}
        </div>

        <p className="text-center text-gray-500 text-xs mt-12">
            Paiement sécurisé via Stripe • Facture disponible instantanément • TVA non incluse
        </p>
    </div>
  );

  const renderCheckout = () => {
    if (!selectedPack) return null;

    const priceHT = selectedPack.price;
    const tva = priceHT * 0.20;
    const totalTTC = priceHT + tva;

    // Logique Upsell
    const showCiterneUpsell = selectedPack.name !== "La Citerne";
    const showSubscriptionUpsell = user?.plan === 'free';

    return (
        <div className="animate-in fade-in slide-in-from-right duration-500">
            <div className="grid lg:grid-cols-12 gap-8">

                {/* Colonne Gauche: Paiement */}
                <div className="lg:col-span-8">
                    <StripeCheckout
                      mode="one-time"
                      productName={selectedPack.name}
                      productDescription={`Pack de ${selectedPack.amount} cr\u00e9dits GTO Gas`}
                      productIcon={selectedPack.icon}
                      amount={totalTTC}
                      amountDetails={[
                        { label: 'Prix Unitaire HT', value: `${priceHT.toFixed(2)} \u20ac` },
                        { label: 'Frais de service', value: '0.00 \u20ac' },
                        { label: 'TVA (20%)', value: `${tva.toFixed(2)} \u20ac` },
                        { label: 'Total TTC', value: `${totalTTC.toFixed(2)} \u20ac`, highlight: true, separator: true },
                      ]}
                      userEmail={user?.email}
                      onConfirm={handleConfirmPayment}
                      onBack={() => setViewMode('list')}
                      isProcessing={isProcessing}
                    />
                </div>

                {/* Colonne Droite: Upsells */}
                <div className="lg:col-span-4 space-y-4">
                    <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wider mb-2">Recommandé pour vous</h3>

                    {/* Upsell Citerne */}
                    {showCiterneUpsell && (
                        <div className="bg-gradient-to-br from-purple-900/40 to-black border border-purple-500/30 p-5 rounded-2xl relative overflow-hidden group cursor-pointer hover:border-purple-500/60 transition-all" onClick={() => setSelectedPack(packs[2])}>
                            <div className="absolute top-0 right-0 px-2 py-1 bg-purple-500 text-white text-[10px] font-bold rounded-bl-lg">
                                Meilleur Prix / Unité
                            </div>
                            <div className="flex items-center gap-3 mb-3">
                                <div className="p-2 bg-purple-500/20 rounded-full text-purple-400">
                                    <Database size={20} />
                                </div>
                                <div>
                                    <h4 className="font-bold text-white text-sm">Passez à la Citerne</h4>
                                    <p className="text-xs text-purple-200/70">Économisez 60%</p>
                                </div>
                            </div>
                            <p className="text-xs text-gray-300 mb-3 leading-relaxed">
                                Obtenez <strong>1000 Crédits</strong> pour seulement 199€. Idéal pour les agences ou les refontes complètes.
                            </p>
                            <button className="w-full py-2 border border-white/[0.08] bg-white/[0.04] rounded-full text-purple-400 text-xs font-bold transition-colors hover:bg-white/[0.08]">
                                Choisir ce pack (199€)
                            </button>
                        </div>
                    )}

                    {/* Upsell Abonnement */}
                    {showSubscriptionUpsell && (
                        <div className="bg-gradient-to-br from-purple-900/40 to-black border border-purple-500/30 p-5 rounded-2xl relative overflow-hidden group cursor-pointer hover:border-purple-500/60 transition-all">
                            <div className="absolute top-0 right-0 px-2 py-1 bg-purple-500 text-white text-[10px] font-bold rounded-bl-lg flex items-center gap-1">
                                <Infinity size={10} /> Mensuel
                            </div>
                            <div className="flex items-center gap-3 mb-3">
                                <div className="p-2 bg-purple-500/20 rounded-full text-purple-400">
                                    <ShieldCheck size={20} />
                                </div>
                                <div>
                                    <h4 className="font-bold text-white text-sm">Activez le Monitoring</h4>
                                    <p className="text-xs text-purple-200/70">La Source</p>
                                </div>
                            </div>
                            <p className="text-xs text-gray-300 mb-3 leading-relaxed">
                                Ne perdez pas vos positions. Ajoutez l'indexation continue et la détection d'hallucinations.
                            </p>
                            <div className="flex items-center gap-2 mb-3">
                                <span className="text-lg font-bold text-white">89€</span>
                                <span className="text-xs text-gray-500">/mois</span>
                            </div>
                            <button className="w-full py-2 btn-gradient text-xs font-bold transition-colors">
                                Ajouter l'abonnement
                            </button>
                        </div>
                    )}

                    {!showCiterneUpsell && !showSubscriptionUpsell && (
                        <div className="p-5 rounded-2xl border border-white/[0.06] bg-white/[0.04] text-center">
                            <div className="w-12 h-12 bg-purple-400/10 rounded-full flex items-center justify-center text-purple-300 mx-auto mb-3">
                                <Check size={24} />
                            </div>
                            <p className="text-sm text-gray-300 font-medium">Vous avez choisi la meilleure offre pour vos besoins !</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
  };

  const renderPaymentResult = () => {
    if (!selectedPack) return null;

    // Status: ERROR
    if (paymentStatus === 'error') {
        return (
            <div className="flex flex-col items-center justify-center min-h-[60vh] animate-in zoom-in duration-500 max-w-2xl mx-auto">
                <div className="w-24 h-24 bg-red-500/20 rounded-full flex items-center justify-center mb-8 border border-red-500/50 shadow-[0_0_40px_rgba(239,68,68,0.3)]">
                    <XCircle size={48} className="text-red-500" />
                </div>

                <h2 className="text-4xl font-bold text-white mb-2">Paiement <span className="gradient-text">Refusé</span></h2>
                <p className="text-gray-500 text-center mb-10 text-lg">
                    La transaction n'a pas pu aboutir. Veuillez vérifier vos informations bancaires ou essayer une autre méthode de paiement.
                </p>

                <div className="flex gap-4 w-full">
                    <button
                        onClick={() => { setViewMode('list'); }}
                        className="flex-1 py-3.5 rounded-full font-bold border border-white/[0.08] bg-white/[0.04] text-white hover:bg-white/[0.08] transition-colors flex items-center justify-center gap-2"
                    >
                        <ArrowLeft size={18} /> Annuler
                    </button>
                    <button
                        onClick={() => { setViewMode('checkout'); }}
                        className="flex-1 py-3.5 btn-gradient font-bold transition-all flex items-center justify-center gap-2"
                    >
                        <RefreshCcw size={18} /> Réessayer
                    </button>
                </div>
            </div>
        );
    }

    // Status: SUCCESS
    const priceHT = selectedPack.price;
    const tva = priceHT * 0.20;
    const totalTTC = priceHT + tva;

    return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] animate-in zoom-in duration-500 max-w-2xl mx-auto">
            <div className="w-24 h-24 bg-purple-400/20 rounded-full flex items-center justify-center mb-8 border border-purple-400/50 shadow-[0_0_40px_rgba(168,85,247,0.3)]">
                <CheckCircle2 size={48} className="text-purple-400" />
            </div>

            <h2 className="text-4xl font-sans font-bold text-white mb-2">Paiement Accepté !</h2>
            <p className="text-gray-500 text-center mb-10 text-lg">
                Merci pour votre commande. Vos crédits <strong>{selectedPack.amount} GTO Gas</strong> ont été ajoutés à votre compte.
            </p>

            <div className="w-full bg-[#0f1115] border border-white/[0.08] rounded-2xl p-8 mb-8 relative overflow-hidden">
                <div className="absolute top-0 right-0 px-3 py-1 bg-white/[0.08] rounded-bl-lg text-xs text-gray-500 font-mono">
                    {invoiceId}
                </div>

                <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                    <FileText size={20} className="text-purple-400" /> Récapitulatif de commande
                </h3>

                <div className="space-y-4 text-sm">
                    <div className="flex justify-between items-center text-gray-300">
                        <span>Produit</span>
                        <span className="font-medium text-white">{selectedPack.name}</span>
                    </div>
                    <div className="flex justify-between items-center text-gray-300">
                        <span>Quantité</span>
                        <span className="font-medium text-white">1</span>
                    </div>
                    <div className="flex justify-between items-center text-gray-300 border-b border-white/[0.08] pb-4">
                        <span>Date</span>
                        <span className="font-medium text-white">{new Date().toLocaleDateString()}</span>
                    </div>
                    <div className="flex justify-between items-center pt-2">
                        <span className="font-bold text-white text-lg">Total Payé</span>
                        <span className="font-bold text-xl text-purple-400">{totalTTC.toFixed(2)} €</span>
                    </div>
                </div>
            </div>

            {/* Buttons Navigation Succès */}
            <div className="flex flex-col md:flex-row gap-4 w-full">
                <button 
                    onClick={() => { onNavigate ? onNavigate('projects') : onBack(); }}
                    className="flex-1 py-3.5 rounded-2xl font-bold bg-white/[0.08] text-white hover:bg-white/20 transition-colors flex items-center justify-center gap-2"
                >
                    <Wrench size={18} /> Continuer l'analyse
                </button>
                <button 
                    onClick={() => { onNavigate ? onNavigate('plan') : console.log("Navigation vers plan non disponible"); }}
                    className="flex-1 py-3.5 rounded-2xl font-bold bg-primary hover:bg-purple-600 text-white transition-all shadow-lg shadow-primary/20 flex items-center justify-center gap-2"
                >
                    <CreditCard size={18} /> Voir Plan & Facturation
                </button>
            </div>

            <button 
                onClick={generateInvoicePDF}
                className="mt-6 text-sm text-gray-500 hover:text-white flex items-center gap-2 transition-colors"
            >
                <Download size={14} /> Télécharger la facture PDF
            </button>
        </div>
    );
  };

  return (
    <div className="w-full px-4 py-10 animate-in fade-in duration-500 min-h-screen">
        {viewMode === 'list' && renderList()}
        {viewMode === 'checkout' && renderCheckout()}
        {viewMode === 'result' && renderPaymentResult()}
    </div>
  );
};

export default Recharge;"}

{"content":"import React from 'react';
import { ArrowLeft, Lock, CreditCard, Loader2, ShieldCheck } from 'lucide-react';

interface StripeCheckoutProps {
  mode: 'subscription' | 'one-time';
  productName: string;
  productDescription: string;
  productIcon?: React.ReactNode;
  amount: number;
  amountDetails?: { label: string; value: string; highlight?: boolean; separator?: boolean }[];
  userEmail?: string;
  onConfirm: () => void;
  onBack: () => void;
  isProcessing: boolean;
  ctaLabel?: string;
}

const StripeCheckout: React.FC<StripeCheckoutProps> = ({
  mode,
  productName,
  productDescription,
  productIcon,
  amount,
  amountDetails,
  userEmail,
  onConfirm,
  onBack,
  isProcessing,
  ctaLabel,
}) => {
  return (
    <div className="w-full max-w-2xl mx-auto">
      {/* Back button */}
      <button
        onClick={onBack}
        disabled={isProcessing}
        className="flex items-center gap-2 text-gray-500 hover:text-white mb-6 transition-colors text-sm"
      >
        <ArrowLeft size={16} /> Retour
      </button>

      <div className="ninja-card rounded-2xl border border-white/[0.08] overflow-hidden">
        {/* Header */}
        <div className="bg-gradient-to-r from-purple-500/10 to-violet-500/10 border-b border-white/[0.06] px-6 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Lock size={16} className="text-purple-400" />
              <span className="text-white font-bold text-sm">Paiement securise</span>
            </div>
            <span className="text-[#635bff] font-bold text-sm tracking-wide">stripe</span>
          </div>
        </div>

        {/* Order summary */}
        <div className="px-6 py-5 border-b border-white/[0.06]">
          <div className="flex items-center gap-4">
            {productIcon && (
              <div className="w-12 h-12 rounded-2xl bg-purple-500/10 flex items-center justify-center text-purple-400 border border-purple-500/20 shrink-0">
                {productIcon}
              </div>
            )}
            <div className="flex-1 min-w-0">
              <h3 className="text-white font-bold text-base truncate">{productName}</h3>
              <p className="text-sm text-gray-500 truncate">{productDescription}</p>
              {mode === 'subscription' && (
                <span className="inline-flex items-center gap-1 mt-1.5 px-2 py-0.5 rounded-full bg-purple-500/10 text-purple-300 text-[10px] font-bold uppercase tracking-wider border border-purple-500/20">
                  Abonnement mensuel
                </span>
              )}
            </div>
          </div>
        </div>

        {/* Amount details */}
        {amountDetails && amountDetails.length > 0 && (
          <div className="px-6 py-4 border-b border-white/[0.06]">
            <div className="space-y-2">
              {amountDetails.map((detail, i) => (
                <React.Fragment key={i}>
                  {detail.separator && (
                    <div className="border-t border-white/[0.06] pt-2" />
                  )}
                  <div className={`flex justify-between items-center text-sm ${
                    detail.highlight ? 'text-white font-bold' : 'text-gray-400'
                  }`}>
                    <span>{detail.label}</span>
                    <span className={detail.highlight ? 'text-purple-400 text-base' : ''}>
                      {detail.value}
                    </span>
                  </div>
                </React.Fragment>
              ))}
            </div>
          </div>
        )}

        {/* STRIPE_INTEGRATION_POINT: Replace the fake form below with Stripe <CardElement> */}
        {/* When integrating Stripe, wrap this component with <Elements> provider */}
        {/* and replace the fake inputs with <CardElement /> from @stripe/react-stripe-js */}
        <div className="px-6 py-5 space-y-4">
          {/* Email */}
          <div>
            <label className="block text-xs font-medium text-gray-500 mb-1.5 uppercase tracking-wider">
              Email (pour le recu)
            </label>
            {/* STRIPE_INTEGRATION_POINT: This email will be passed to Stripe checkout session */}
            <input
              type="email"
              defaultValue={userEmail || ''}
              placeholder="email@exemple.com"
              className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-white text-sm placeholder-gray-600 focus:border-purple-500/50 focus:outline-none transition-colors"
            />
          </div>

          {/* Card holder */}
          <div>
            <label className="block text-xs font-medium text-gray-500 mb-1.5 uppercase tracking-wider">
              Titulaire de la carte
            </label>
            {/* STRIPE_INTEGRATION_POINT: Card holder name */}
            <input
              type="text"
              placeholder="Jean Dupont"
              className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-white text-sm placeholder-gray-600 focus:border-purple-500/50 focus:outline-none transition-colors"
            />
          </div>

          {/* Card number */}
          <div>
            <label className="block text-xs font-medium text-gray-500 mb-1.5 uppercase tracking-wider">
              Numero de carte
            </label>
            {/* STRIPE_INTEGRATION_POINT: Replace with <CardNumberElement /> */}
            <div className="relative">
              <input
                type="text"
                placeholder="4242 4242 4242 4242"
                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl pl-10 pr-4 py-2.5 text-white text-sm placeholder-gray-600 focus:border-purple-500/50 focus:outline-none transition-colors"
              />
              <CreditCard size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
            </div>
          </div>

          {/* Expiration + CVC */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-medium text-gray-500 mb-1.5 uppercase tracking-wider">
                Expiration
              </label>
              {/* STRIPE_INTEGRATION_POINT: Replace with <CardExpiryElement /> */}
              <input
                type="text"
                placeholder="MM / AA"
                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-white text-sm placeholder-gray-600 focus:border-purple-500/50 focus:outline-none transition-colors"
              />
            </div>
            <div>
              <label className="block text-xs font-medium text-gray-500 mb-1.5 uppercase tracking-wider">
                CVC
              </label>
              {/* STRIPE_INTEGRATION_POINT: Replace with <CardCvcElement /> */}
              <input
                type="text"
                placeholder="123"
                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-white text-sm placeholder-gray-600 focus:border-purple-500/50 focus:outline-none transition-colors"
              />
            </div>
          </div>
        </div>

        {/* CTA Button */}
        <div className="px-6 pb-5">
          <button
            onClick={onConfirm}
            disabled={isProcessing}
            className="w-full py-3.5 bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-all shadow-lg shadow-purple-500/20 disabled:opacity-60 disabled:cursor-not-allowed"
          >
            {isProcessing ? (
              <>
                <Loader2 size={18} className="animate-spin" />
                Traitement en cours...
              </>
            ) : (
              <>
                <Lock size={16} />
                {ctaLabel || `Payer ${amount.toFixed(2)} \u20ac`}
              </>
            )}
          </button>
        </div>

        {/* Trust badges */}
        <div className="px-6 pb-4">
          <div className="flex items-center justify-center gap-4 text-[10px] text-gray-600">
            <span className="flex items-center gap-1">
              <ShieldCheck size={12} className="text-green-500/70" />
              SSL 256-bit
            </span>
            <span className="text-gray-700">|</span>
            <span>
              Powered by <span className="text-[#635bff] font-bold">stripe</span>
            </span>
            <span className="text-gray-700">|</span>
            <span className="flex items-center gap-1">
              <Lock size={10} />
              Chiffre
            </span>
          </div>
        </div>

        {/* Legal */}
        <div className="px-6 pb-5">
          <p className="text-[10px] text-gray-600 text-center leading-relaxed">
            En cliquant sur "Payer", vous acceptez nos{' '}
            <button className="text-purple-400/70 hover:text-purple-300 underline transition-colors">
              Conditions Generales de Vente
            </button>
            .{' '}
            {mode === 'subscription' && "Votre abonnement sera renouvel\u00e9 automatiquement chaque mois."}
          </p>
        </div>
      </div>
    </div>
  );
};

export default StripeCheckout;
"}

{"content":"import React, { useState, useRef, useCallback } from 'react';
import { Sparkles, TrendingUp, Target, Award, MousePointerClick, ArrowRight, ScanLine, Code2, Globe2, Fuel, Zap, Star, Check, Search, Bot, BrainCircuit, Database, Share2, Layers, Infinity, Radio, Globe, Droplet, Loader2, Gift, Shield, UserCheck, GraduationCap, BadgeCheck } from 'lucide-react';
import { User } from '../types';
import ScoreRing from '../components/ScoreRing';
import { auditAnswerFirst, AnswerFirstAuditResult } from '../services/answer-first-audit';

interface HomeProps {
  onNavigate: (view: 'analyze' | 'login' | 'recharge' | 'directory') => void;
  user: User | null;
  onDirectRecharge?: (packId: number) => void;
}

const Home: React.FC<HomeProps> = ({ onNavigate, user, onDirectRecharge }) => {

  // ── Score Gratuit State ──
  const [brandName, setBrandName] = useState('');
  const [siteUrl, setSiteUrl] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [auditResult, setAuditResult] = useState<AnswerFirstAuditResult | null>(null);
  const [auditError, setAuditError] = useState<string | null>(null);
  const resultsRef = useRef<HTMLDivElement>(null);

  // Derive E-E-A-T pillar scores from the 6 audit categories
  const eeatPillars = auditResult ? [
    { label: 'Experience', icon: <UserCheck size={16} />, score: Math.round((auditResult.categories.contentFreshness.score + auditResult.categories.answerFirst.score) / 2) },
    { label: 'Expertise', icon: <GraduationCap size={16} />, score: Math.round((auditResult.categories.faqStructure.score + auditResult.categories.semanticHtml.score) / 2) },
    { label: 'Authority', icon: <BadgeCheck size={16} />, score: Math.round((auditResult.categories.schemaOrg.score + auditResult.categories.metaOptimization.score) / 2) },
    { label: 'Trust', icon: <Shield size={16} />, score: Math.round((auditResult.categories.metaOptimization.score + auditResult.categories.schemaOrg.score + auditResult.categories.answerFirst.score) / 3) },
  ] : [];

  const handleFreeAudit = useCallback(async () => {
    if (!brandName.trim() || !siteUrl.trim()) {
      setAuditError('Veuillez remplir les deux champs.');
      return;
    }
    // Basic URL validation
    let finalUrl = siteUrl.trim();
    if (!/^https?:\/\//i.test(finalUrl)) {
      finalUrl = 'https://' + finalUrl;
    }
    try {
      new URL(finalUrl);
    } catch {
      setAuditError('URL invalide. Exemple : https://www.example.com');
      return;
    }

    setAuditError(null);
    setAuditResult(null);
    setIsAnalyzing(true);

    try {
      const result = await auditAnswerFirst(finalUrl, brandName.trim());
      setAuditResult(result);
      // Scroll to results after a small delay for render
      setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }, 150);
    } catch (err) {
      setAuditError('Une erreur est survenue lors de l\'analyse. Veuillez reessayer.');
    } finally {
      setIsAnalyzing(false);
    }
  }, [brandName, siteUrl]);

  const getScoreLabel = (score: number): string => {
    if (score >= 80) return 'Excellent';
    if (score >= 60) return 'Bon';
    if (score >= 40) return 'Moyen';
    if (score >= 20) return 'Faible';
    return 'Critique';
  };

  const getScoreColor = (score: number): string => {
    if (score >= 80) return 'text-purple-400';
    if (score >= 60) return 'text-violet-400';
    if (score >= 40) return 'text-amber-400';
    return 'text-red-400';
  };

  const getBarColor = (score: number): string => {
    if (score >= 80) return 'bg-purple-500';
    if (score >= 60) return 'bg-violet-500';
    if (score >= 40) return 'bg-amber-500';
    return 'bg-red-500';
  };

  const handleStartAnalysis = () => {
    if (user) {
      onNavigate('analyze');
    } else {
      onNavigate('login');
    }
  };

  const handleSelectPlan = (packId: number) => {
    if (user) {
      if (onDirectRecharge) {
        onDirectRecharge(packId);
      } else {
        onNavigate('recharge');
      }
    } else {
      onNavigate('login');
    }
  };

  const plans = [
    {
      id: 1,
      name: "Le Jerrican",
      credits: 50,
      price: 15,
      icon: <Droplet size={24} />,
      popular: false,
      features: ["Id\u00e9al pour tester", "1 Audit complet", "Valable 1 an"]
    },
    {
      id: 2,
      name: "La Pompe",
      credits: 200,
      price: 49,
      icon: <Fuel size={24} />,
      popular: true,
      features: ["Pour optimiser s\u00e9rieusement", "Support prioritaire", "+10% Bonus offert"]
    },
    {
      id: 3,
      name: "La Citerne",
      credits: 1000,
      price: 199,
      icon: <Database size={24} />,
      popular: false,
      features: ["Usage intensif / Agence", "Acc\u00e8s API Beta", "+20% Bonus offert"]
    }
  ];

  return (
    <div className="w-full px-6 pt-16 pb-32 overflow-hidden">

      {/* ── HERO SECTION ── */}
      <div className="text-center mb-32 relative">
        {/* Ambient glow */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[700px] h-[500px] bg-purple-600/8 blur-[150px] rounded-full -z-10 pointer-events-none"></div>

        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.04] border border-white/[0.08] text-gray-400 text-xs font-medium tracking-wide uppercase mb-10">
          <Sparkles size={12} className="text-purple-400" />
          <span>Plateforme AEO / GEO</span>
        </div>

        <h1 className="text-5xl sm:text-6xl md:text-[5.5rem] font-sans font-bold tracking-tight text-white leading-[1.05] mb-8">
          Faites-vous citer{' '}
          <br className="hidden md:block" />
          par les <span className="gradient-text">IA G{'\u00e9'}n{'\u00e9'}ratives</span>
        </h1>

        <p className="text-lg md:text-xl text-gray-500 max-w-2xl mx-auto leading-relaxed mb-12 font-light">
          La premi{'\u00e8'}re plateforme d'optimisation AEO. Analysez et influencez la fa{'\u00e7'}on dont ChatGPT, Claude et Gemini per{'\u00e7'}oivent votre marque.
        </p>

        <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
          <button onClick={handleStartAnalysis} className="btn-gradient text-base px-8 py-3.5 flex items-center gap-2.5 shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30">
            Lancer un Audit Gratuit <ArrowRight size={18} />
          </button>
          <button onClick={() => onNavigate('directory')} className="px-8 py-3.5 rounded-full border border-white/[0.1] text-gray-300 text-base font-medium hover:bg-white/[0.04] hover:border-white/[0.15] transition-all">
            Explorer l'Annuaire
          </button>
        </div>
      </div>

      {/* ── SCORE GRATUIT DE VISIBILITE IA ── */}
      <div className="mb-32 relative" id="score-gratuit">
        {/* Ambient glow */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[600px] bg-purple-600/[0.06] blur-[180px] rounded-full -z-10 pointer-events-none"></div>

        {/* Section header */}
        <div className="text-center mb-12">
          {/* GRATUIT Banner */}
          <div className="inline-flex items-center gap-2 px-5 py-2 rounded-full bg-gradient-to-r from-purple-500/20 to-violet-600/20 border border-purple-500/30 text-white text-sm font-bold tracking-wide uppercase mb-8 shadow-lg shadow-purple-600/10">
            <Gift size={16} className="text-purple-400" />
            <span>100% GRATUIT</span>
            <span className="text-purple-400">&mdash;</span>
            <span className="text-purple-300">Sans inscription</span>
          </div>

          <h2 className="text-3xl md:text-5xl font-sans font-bold text-white tracking-tight mb-5">
            Votre Score de <span className="gradient-text">Visibilit{'\u00e9'} IA</span>
          </h2>
          <p className="text-gray-500 max-w-2xl mx-auto text-lg">
            D{'\u00e9'}couvrez en 30 secondes comment les IA g{'\u00e9'}n{'\u00e9'}ratives per{'\u00e7'}oivent votre marque. Aucun compte requis.
          </p>
        </div>

        {/* Form + Results Container */}
        <div className="max-w-3xl mx-auto">
          {/* Form Card */}
          <div className="ninja-card p-8 md:p-10 relative overflow-hidden">
            {/* Decorative gradient line at top */}
            <div className="absolute top-0 left-0 right-0 h-[2px] bg-gradient-to-r from-transparent via-purple-500 to-transparent"></div>

            <form
              onSubmit={(e) => { e.preventDefault(); handleFreeAudit(); }}
              className="space-y-5"
            >
              <div className="grid md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-2">Nom de marque</label>
                  <input
                    type="text"
                    value={brandName}
                    onChange={(e) => setBrandName(e.target.value)}
                    placeholder="Ex: CitedBy"
                    className="w-full px-4 py-3 rounded-xl bg-white/[0.04] border border-white/[0.08] text-white placeholder-gray-600 outline-none transition-all focus:border-purple-500/50 focus:bg-white/[0.06] focus:shadow-[0_0_20px_rgba(168,85,247,0.08)]"
                    disabled={isAnalyzing}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-2">URL du site</label>
                  <input
                    type="text"
                    value={siteUrl}
                    onChange={(e) => setSiteUrl(e.target.value)}
                    placeholder="Ex: https://www.citedby.ai"
                    className="w-full px-4 py-3 rounded-xl bg-white/[0.04] border border-white/[0.08] text-white placeholder-gray-600 outline-none transition-all focus:border-purple-500/50 focus:bg-white/[0.06] focus:shadow-[0_0_20px_rgba(168,85,247,0.08)]"
                    disabled={isAnalyzing}
                  />
                </div>
              </div>

              {auditError && (
                <p className="text-sm text-red-400 bg-red-500/10 border border-red-500/20 rounded-xl px-4 py-2.5">{auditError}</p>
              )}

              <button
                type="submit"
                disabled={isAnalyzing}
                className="w-full btn-gradient py-4 text-base font-bold flex items-center justify-center gap-3 shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30 disabled:opacity-60 disabled:cursor-not-allowed transition-all"
              >
                {isAnalyzing ? (
                  <>
                    <Loader2 size={20} className="animate-spin" />
                    Analyse en cours...
                  </>
                ) : (
                  <>
                    <Sparkles size={20} />
                    Analyser gratuitement
                  </>
                )}
              </button>

              <p className="text-center text-xs text-gray-600">
                Aucune carte bancaire requise. 0 GTO Gas consomm{'\u00e9'}. R{'\u00e9'}sultat instantan{'\u00e9'}.
              </p>
            </form>
          </div>

          {/* Loading Animation */}
          {isAnalyzing && (
            <div className="mt-8 ninja-card p-10 flex flex-col items-center justify-center gap-5">
              <div className="relative">
                <div className="w-24 h-24 rounded-full border-4 border-white/[0.06]"></div>
                <div className="absolute inset-0 w-24 h-24 rounded-full border-4 border-transparent border-t-purple-500 animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                  <ScanLine size={28} className="text-purple-400 animate-pulse" />
                </div>
              </div>
              <div className="text-center">
                <p className="text-white font-semibold mb-1">Scan en cours...</p>
                <p className="text-sm text-gray-500">Nous interrogeons les LLMs pour {'\u00e9'}valuer votre marque</p>
              </div>
              {/* Animated category tags */}
              <div className="flex flex-wrap justify-center gap-2">
                {['Answer-First', 'Schema.org', 'FAQ', 'S\u00e9mantique', 'Fra\u00eecheur', 'Meta'].map((label, i) => (
                  <div
                    key={label}
                    className="px-3 py-1 rounded-full text-[10px] font-medium bg-white/[0.04] border border-white/[0.06] text-gray-500"
                    style={{ animation: `pulse 1.5s ease-in-out ${i * 0.25}s infinite` }}
                  >
                    {label}
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Results Section */}
          {auditResult && !isAnalyzing && (
            <div ref={resultsRef} className="mt-8 space-y-6">
              {/* Main Score Card */}
